INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-10', E'침략자 곡에 대한 심판과 멸망 (에스겔 39장)', E'에스겔 39장', E'에스겔 39장은 38장에서 시작된 곡에 대한 심판 예언이 절정에 이르는 장면을 보여줍니다. 하나님께서는 북방의 강대국 곡을 이끌어내어 이스라엘 산 위에서 완전히 멸망시키실 것을 선포하십니다. 곡의 군대가 얼마나 강력했는지는 그들의 무기를 7년 동안 땔감으로 사용할 정도라는 표현에서 잘 드러납니다. 그러나 하나님께서는 이 거대한 군대를 순식간에 무너뜨리시고, 그들의 시체가 이스라엘 땅에 가득할 것이라고 말씀하십니다.\n\n이 심판의 목적은 단순한 보복이 아니었습니다. "내가 여호와 곧 이스라엘의 거룩한 자인 줄을 민족들이 알리라"(겔 39:7)는 말씀처럼, 하나님께서는 당신의 거룩한 이름을 모든 민족 가운데 알리고자 하셨습니다. 곡의 멸망은 하나님의 주권과 능력을 온 세상에 증명하는 사건이 될 것입니다. \n\n특별히 주목할 것은 25절 이후에 나타나는 회복의 약속입니다. 하나님께서는 심판 이후에 "야곱의 사로잡힌 자를 돌아오게 하며 이스라엘 온 족속에게 사랑을 베풀지라"고 약속하십니다. 포로로 잡혀간 백성들은 이방 땅에서 하나님의 얼굴을 보지 못한다고 절망했을 것입니다. 그러나 하나님께서는 그들을 한 사람도 남김없이 고향으로 돌아오게 하시고, 더 나아가 성령을 부어주실 것을 약속하십니다.\n\n이 약속은 단순한 지리적 귀환을 넘어 영적인 회복을 의미합니다. 하나님께서 다시는 얼굴을 가리지 않으시고 성령을 부어주신다는 것은 하나님과 백성 사이의 관계가 완전히 회복될 것을 보여줍니다. 심판의 어두운 그림자 속에서도 하나님의 변함없는 사랑과 신실하심이 빛나고 있습니다.', E'오늘의 핵심\n하나님께서는 곡의 완전한 멸망을 통해 당신의 거룩함을 만방에 드러내시고, 동시에 이스라엘의 완전한 회복을 약속하심으로써 심판 너머에 있는 구원의 소망을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판이 궁극적으로 당신의 거룩함을 드러내기 위함임을 어떻게 이해하고 계신가요?\n2. 포로 생활의 절망 속에서도 하나님의 회복 약속을 붙잡는 믿음이 내게 있나요?\n3. 하나님께서 성령을 부어주신다는 약속이 오늘 나의 삶에 어떤 의미로 다가옵니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-11', E'하나님의 본뜻 (에스겔 42장)', E'에스겔 42장', E'에스겔이 성전 환상 가운데 보게 된 것은 단순한 건축물의 설계도가 아니었습니다. 하나님께서는 성전 북쪽과 남쪽에 있는 제사장들의 방을 상세히 보여주시면서, 거룩한 공간이 어떻게 구별되어야 하는지를 가르쳐 주십니다. 이 방들은 "거룩한 방"으로, 여호와를 가까이하는 제사장들이 지성물을 먹는 곳이자 소제와 속죄제, 속건제의 제물을 보관하는 곳이었습니다.\n\n특히 주목할 것은 제사장들의 의복에 관한 규정입니다. 성소에서 수종들던 거룩한 의복을 입은 채로는 백성의 뜰로 나갈 수 없었습니다. 반드시 그 의복을 벗어 거룩한 방에 두고 다른 옷으로 갈아입어야 했습니다. 이는 거룩한 것과 일상적인 것의 경계를 분명히 하라는 하나님의 명령이었습니다.\n\n성전 측량의 마지막 장면도 의미심장합니다. 동서남북 각 오백 척씩 정확히 같은 크기로 측량된 성전의 사방 담은 "거룩한 것과 속된 것을 구별하는" 경계선이었습니다. 이전 성전이 무너진 이유 중 하나가 바로 이 경계의 붕괴였음을 생각할 때, 하나님께서는 새 성전에서 그 구별을 더욱 철저히 하고자 하신 것입니다.\n\n포로 된 백성에게 이런 환상을 보여주신 것은 단순히 미래의 건축 계획을 알려주시려는 것이 아니었습니다. 하나님께서는 "내가 여전히 거룩하며, 너희도 거룩해야 한다"는 변하지 않는 원칙을 가르치고 계셨습니다. 비록 지금은 이방 땅에 흩어져 있지만, 하나님의 백성으로서의 정체성을 잃지 말고, 거룩과 속된 것을 구별하는 삶을 살아가라는 메시지였습니다.\n\n오늘 우리의 삶에도 이런 구별이 필요합니다. 세상 속에 살지만 세상에 물들지 않고, 하나님의 거룩하심을 담아내는 그릇이 되어야 합니다. 내 삶의 어떤 영역에서 거룩한 것과 속된 것의 경계가 흐려지고 있는지 돌아보며, 다시 그 경계를 분명히 세워가시기 바랍니다.', E'오늘의 핵심\n하나님께서는 새 성전의 거룩한 공간과 제사장 규례를 통해, 거룩과 속된 것을 철저히 구별하는 삶의 원칙을 가르치십니다.\n\n묵상 질문\n1. 내 삶에서 거룩한 것과 일상적인 것의 경계가 흐려진 부분은 어디일까요?\n2. 하나님께서 나에게 요구하시는 ''구별된 삶''의 구체적인 모습은 무엇일까요?\n3. 포로 상황에서도 거룩함을 포기하지 않으신 하나님의 마음을 어떻게 받아들이고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-12', E'하나님의 본뜻 (에스겔 43장)', E'에스겔 43장', E'예루살렘이 함락되고 성전이 불탄 지 14년, 포로로 끌려간 에스겔에게 하나님께서 놀라운 환상을 보여주십니다. 동쪽 문으로 하나님의 영광이 들어오는데, 그 음성은 많은 물 소리 같고 땅은 그 영광으로 빛났습니다. 에스겔이 본 것은 단순한 건물이 아니라 하나님의 영광이 가득한 성전이었습니다.\n\n하나님께서는 "이는 내 보좌의 처소, 내 발을 두는 처소, 내가 이스라엘 족속 가운데에 영원히 있을 곳이라"(겔 43:7)고 선언하십니다. 이 말씀은 포로 생활로 절망하던 백성들에게 놀라운 약속이었습니다. 하나님이 다시 그들과 함께하시겠다는 것입니다. 그러나 과거를 돌아보게도 하십니다. 백성들이 성전 바로 곁에 우상의 문지방을 두고, 겨우 한 담만을 사이에 둔 채 가증한 일을 행했던 것을 지적하십니다.\n\n하나님께서는 제단의 치수와 정결 예식을 상세히 알려주십니다. 7일 동안 매일 속죄제물을 드려 제단을 정결하게 하라고 명령하십니다. 이는 단순한 의식이 아닙니다. 거룩하신 하나님과 만나기 위해서는 철저한 회개와 정결함이 필요하다는 가르침입니다. 속죄의 피가 제단의 네 뿔과 모퉁이, 가장자리에 발라져야 했습니다. 구석구석 남김없이 정결하게 되어야 한다는 뜻입니다.\n\n오늘 우리에게도 하나님은 같은 질문을 하십니다. 우리 마음의 성전은 어떠한가요? 하나님의 보좌 바로 곁에 세상의 가치관과 욕망의 문지방을 슬쩍 세워두고 있지는 않은지요. 하나님께서는 우리와 영원히 함께하기를 원하십니다. 그러나 그분의 거룩하심과 우리의 죄악은 양립할 수 없습니다. 회개와 정결함으로 나아갈 때, 하나님의 영광이 우리 삶에 충만하게 임할 것입니다.', E'오늘의 핵심\n하나님께서는 무너진 성전의 회복을 약속하시며, 백성들이 철저히 회개하고 정결하게 될 때 그들 가운데 영원히 거하시겠다고 선언하십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님이 회복의 비전을 보여주신다는 사실이 내게 어떤 위로가 됩니까?\n2. 내 삶에서 하나님의 거룩함 바로 곁에 두고 있는 ''세상의 문지방''은 무엇일까요?\n3. 하나님과의 온전한 만남을 위해 오늘 내가 정결하게 해야 할 영역은 무엇입니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-13', E'회복과 새로운 땅 (에스겔 44장)', E'에스겔 44장', E'성전으로 돌아오신 여호와의 영광 앞에서 에스겔은 엎드릴 수밖에 없었습니다. 하나님께서는 동문으로 들어오신 후 그 문을 영원히 닫으라고 명하십니다. 이는 다시는 하나님께서 성전을 떠나지 않으시겠다는 약속의 상징입니다. 한 번 파괴되었던 성전, 하나님의 영광이 떠났던 그곳에 이제 영원한 임재를 선언하시는 것입니다.\n\n하나님은 과거 성전이 더럽혀진 이유를 분명히 지적하십니다. 할례받지 않은 이방인들이 성소에 들어와 있었고, 레위인들조차 우상을 따라 하나님을 떠났습니다. 그들은 자신들의 직분을 다른 이에게 맡기고 성전의 거룩함을 지키지 못했습니다. 하나님의 집이 시장터처럼 변질되었던 과거의 실패를 상기시키시는 것입니다.\n\n그러나 하나님의 은혜는 여기서도 빛납니다. 비록 레위인들이 죄를 지었지만, 완전히 버리지 않으시고 성전에서 수종드는 일을 맡기십니다. 다만 제사장 직분은 행할 수 없게 하심으로써 죄에는 분명한 결과가 따름을 보여주십니다. 은혜와 공의가 균형을 이루는 하나님의 다스리심을 봅니다.\n\n특별히 주목할 것은 사독의 자손들입니다. "이스라엘 족속이 그릇 행하여 나를 떠날 때에 사독의 자손 레위 사람 제사장들은 내 성소의 직분을 지켰은즉"(15절) 하나님은 그들의 충성을 잊지 않으셨습니다. 모두가 타락할 때 홀로 자리를 지킨 이들에게 가장 가까이에서 하나님을 섬기는 특권이 주어집니다.\n\n새 성전의 제사장들에게 주어진 규례들은 거룩함을 유지하기 위한 구체적 지침들입니다. 옷차림부터 결혼, 일상생활에 이르기까지 세세한 규정들이 주어집니다. 이는 단순한 율법주의가 아니라, 하나님과 백성 사이의 중보자로서 그들이 얼마나 거룩해야 하는지를 보여줍니다.\n\n오늘 우리도 왕 같은 제사장으로 부름받았습니다. 세상이 하나님을 떠날 때, 우리는 사독의 자손처럼 맡은 자리를 지키고 있습니까? 거룩함을 잃어버린 시대 속에서 구별된 삶을 살아가는 것, 그것이 이 시대 하나님의 제사장된 우리의 사명입니다.', E'오늘의 핵심\n하나님께서는 과거의 실패를 지적하시면서도 새 성전에서 충성된 자들에게 특별한 직분을 맡기시며, 거룩함을 지키는 구체적인 삶의 원칙을 제시하십니다.\n\n묵상 질문\n1. 모두가 타락할 때에도 자리를 지킨 사독의 자손처럼, 나는 어떤 영역에서 신실함을 지켜야 할까요?\n2. 하나님께서 내게 맡기신 직분과 자리를 다른 것에 위임하고 있지는 않나요?\n3. 거룩한 삶을 위해 오늘 내가 구별해야 할 구체적인 영역은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-14', E'회복과 새로운 땅 (에스겔 45장)', E'에스겔 45장', E'에스겔서 45장은 회복된 이스라엘의 새로운 토지 분배와 예배 규정을 담고 있습니다. 포로로 끌려간 백성들에게 이 말씀은 단순한 미래의 청사진이 아니라, 하나님께서 여전히 그들과 함께하시며 새로운 시작을 준비하고 계신다는 확실한 약속이었습니다.\n\n하나님은 먼저 거룩한 구역을 구별하여 성소와 제사장들, 레위인들을 위한 땅을 정하십니다. 성전을 중심으로 한 이 새로운 배치는 하나님께서 다시 그들 가운데 거하실 것임을 보여줍니다. 또한 왕에게도 일정한 땅을 할당하시되, "나의 왕들이 다시는 내 백성을 압제하지 아니하리라"(겔 45:8)고 선언하십니다. 과거 왕들이 백성의 땅을 빼앗고 억압했던 역사가 반복되지 않도록 제도적 장치를 마련하신 것입니다.\n\n특히 주목할 점은 하나님께서 공정한 저울과 도량형을 강조하시는 부분입니다. 에바와 밧, 세겔의 정확한 기준을 제시하시며 경제 정의를 세우고자 하십니다. 예배와 일상, 성전과 시장이 분리되지 않고 하나님의 공의로 연결되어야 함을 가르치십니다. \n\n또한 군주가 백성을 위해 제사를 준비하는 책임을 지도록 규정하십니다. 명절과 안식일마다 번제와 소제를 갖추는 것이 왕의 의무가 됩니다. 권력은 섬김을 위해 존재한다는 하나님의 원칙이 여기에 담겨 있습니다.\n\n유월절과 초막절 규정을 상세히 제시하시는 하나님의 마음에는 과거 출애굽의 은혜를 잊지 않기를 바라시는 뜻이 담겨 있습니다. 포로 생활 중에도 하나님은 여전히 구원의 하나님이시며, 그들을 다시 이끌어내실 분이라는 메시지입니다. \n\n오늘 우리의 삶에도 하나님께서는 거룩한 구역을 정하기 원하십니다. 예배의 자리, 정의의 저울, 섬김의 리더십 - 이 모든 것이 하나님의 나라를 이루는 요소들입니다. 혼란한 시대 속에서도 하나님의 질서를 따라 살아가는 것, 그것이 회복을 준비하는 길입니다.', E'오늘의 핵심\n하나님께서는 새로운 이스라엘 공동체의 청사진을 제시하시며, 예배와 정의, 리더십의 올바른 질서를 회복시키겠다고 약속하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님께 구별하여 드려야 할 ''거룩한 구역''은 무엇일까요?\n2. 일상에서 실천할 수 있는 ''공정한 저울''의 정신은 어떤 모습일까요?\n3. 섬기는 리더십으로 나를 변화시키기 위해 오늘 무엇을 시작할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-15', E'회복과 새로운 땅 (에스겔 46장)', E'에스겔 46장', E'에스겔이 본 새 성전의 환상은 계속 이어집니다. 이번에는 성전 예배의 구체적인 규례들이 제시되는데, 특별히 안식일과 초하루의 예배, 그리고 군주와 백성이 드리는 제사의 규정이 상세하게 기록되어 있습니다. 바벨론 포로로 끌려가 성전 없이 지내야 했던 이스라엘 백성에게 이 말씀은 어떤 의미였을까요? 그것은 하나님께서 다시 그들과 함께하실 것이며, 예배의 질서가 회복될 것이라는 소망의 메시지였습니다.\n\n주목할 점은 예배의 중심에 ''군주''가 등장한다는 것입니다. 이 군주는 백성을 대표하여 하나님께 나아가되, 스스로 제사를 드리지는 못합니다. 제사장이 그를 위해 번제와 감사제를 드리고, 군주는 문 통로에서 예배합니다. 이는 왕권과 제사장직이 분명히 구별되어야 함을 보여줍니다. 과거 웃시야 왕이 제사장의 직무를 침범하다가 나병에 걸렸던 일을 기억한다면, 이러한 질서의 중요성을 더욱 깊이 이해할 수 있습니다.\n\n또한 백성들이 북문으로 들어온 자는 남문으로 나가고, 남문으로 들어온 자는 북문으로 나가도록 한 규정도 의미심장합니다. "들어온 문으로 도로 나가지 말고 그 몸이 앞으로 향한 대로 나갈지며"(겔 46:9)라는 말씀은 예배자가 하나님을 만난 후에는 결코 예전의 모습으로 돌아갈 수 없음을 상징적으로 보여줍니다. 참된 예배는 우리를 변화시키고 새로운 방향으로 나아가게 합니다.\n\n한편, 군주의 기업 상속에 관한 규정도 눈여겨볼 만합니다. 군주는 백성의 기업을 빼앗아서는 안 되며, 자기 아들에게 줄 것은 자기 산업으로만 해야 합니다. 이는 아합이 나봇의 포도원을 빼앗았던 과거의 악행이 반복되지 않도록 하는 안전장치입니다. 하나님의 나라에서는 권력자라 할지라도 약자의 권리를 침해할 수 없습니다.\n\n마지막으로 성전 뜰의 부엌에 대한 묘사가 나옵니다. 거룩한 제사와 함께 일상적인 음식 준비의 공간까지 세심하게 계획하신 하나님의 배려가 느껴집니다. 예배는 거룩한 의식만이 아니라 백성의 삶 전체를 아우르는 것임을 알 수 있습니다. 오늘 우리의 예배도 마찬가지입니다. 주일 예배당에서의 경건함이 월요일 일터에서의 정직함으로 이어질 때, 그것이 진정한 예배입니다.', E'오늘의 핵심\n에스겔이 본 새 성전의 예배 규례는 질서 있는 예배를 통해 하나님과 백성이 만나고, 그 만남이 삶의 변화로 이어져야 함을 보여줍니다.\n\n묵상 질문\n1. 나는 예배를 통해 어떤 변화를 경험하고 있나요? 들어온 문으로 되돌아가지 않고 앞으로 나아가고 있나요?\n2. 내가 가진 권한이나 영향력을 다른 사람의 유익을 위해 사용하고 있나요, 아니면 나의 욕심을 채우는 데 사용하고 있나요?\n3. 주일의 예배가 일상의 삶으로 어떻게 연결되어야 할까요? 오늘 실천할 수 있는 한 가지는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-17', E'회복과 새로운 땅 (에스겔 47장)', E'에스겔 47장', E'포로로 끌려간 에스겔에게 하나님께서 보여주신 새 성전의 환상은 절정을 향해 나아갑니다. 성전 문지방 밑에서 시작된 작은 물줄기가 점차 깊어져 마침내 헤엄쳐야 할 만큼 큰 강이 되는 장면은, 하나님의 생명력이 얼마나 풍성한지를 보여줍니다. 처음에는 발목에 오르던 물이 무릎에, 허리에, 그리고 마침내는 건널 수 없는 강이 됩니다. 이 점진적인 깊어짐은 하나님의 은혜가 우리 삶에 임하는 방식을 떠올리게 합니다.\n\n더욱 놀라운 것은 이 강물이 흘러가는 곳마다 일어나는 변화입니다. 죽음의 바다로 알려진 사해까지도 이 물이 이르면 살아나고, 고기가 번성하며, 어부들이 그물을 치게 됩니다. 강 좌우에는 열매가 끊이지 않는 나무들이 자라며, 그 잎은 치료하는 약이 됩니다. 성전에서 흘러나온 물이 온 땅에 생명과 치유, 풍요를 가져오는 것입니다.\n\n이어서 하나님께서는 회복될 이스라엘의 경계를 분명히 하십니다. 흥미롭게도 이 땅의 분배에는 이스라엘 백성뿐 아니라 그들 가운데 거하는 타국인들도 포함됩니다. "너희는 그 타국인을 본토에서 난 이스라엘 족속 같이 여기고"(겔 47:22)라는 말씀은 하나님의 은혜가 민족의 경계를 넘어섬을 보여줍니다.\n\n바벨론의 포로로 절망 가운데 있던 백성들에게 이 환상은 단순한 위로를 넘어 확실한 소망이었습니다. 지금은 비록 약속의 땅에서 쫓겨났지만, 하나님께서는 더 영광스러운 회복을 준비하고 계셨던 것입니다. 성전에서 흘러나오는 생명의 강은 오늘 우리에게도 동일하게 흐르고 있습니다. 메마른 우리의 영혼과 삶의 현장에 하나님의 생명수가 스며들어 새로운 생명력을 불어넣기를 갈망합니다.', E'오늘의 핵심\n성전에서 흘러나온 물이 온 땅에 생명을 가져오는 환상은, 하나님께서 주시는 은혜가 점진적으로 깊어지며 모든 것을 새롭게 한다는 약속입니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 은혜가 발목에서 시작해 점점 깊어진 경험이 있나요?\n2. 죽음의 바다 같은 내 삶의 영역이 하나님의 생명수로 회복될 수 있다고 믿으시나요?\n3. 하나님의 은혜가 ''타국인''처럼 소외된 이들에게까지 미친다는 말씀이 오늘 나에게 주는 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-18', E'회복과 새로운 땅 (에스겔 48장)', E'에스겔 48장', E'에스겔서의 대단원의 막을 내리는 48장은 회복된 이스라엘의 땅 분배와 새 예루살렘 성읍의 청사진을 보여줍니다. 포로로 끌려간 백성들에게 이 환상은 단순한 지도가 아니라, 하나님께서 여전히 그들을 당신의 백성으로 여기신다는 확실한 증거였습니다.\n\n각 지파에게 땅을 분배하시는 하나님의 모습은 여호수아 시대를 떠올리게 합니다. 한 가지 다른 점은 이제 모든 지파가 동일한 크기의 땅을 받는다는 것입니다. 과거의 불평등이나 차별 없이, 하나님 앞에서 모두가 동등한 상속자로 인정받습니다. 특별히 사독의 자손들은 "이스라엘 족속이 그릇될 때에... 그릇되지 아니하였느니라"(겔 48:11)는 평가와 함께 가장 거룩한 땅을 받습니다. 어두운 시대에도 신실함을 지킨 이들을 하나님은 기억하고 계셨던 것입니다.\n\n더욱 놀라운 것은 성읍의 새 이름입니다. ''여호와 삼마'' - ''여호와께서 거기 계시다''는 뜻입니다. 성전이 파괴되고 하나님의 영광이 떠났던 그 자리에, 이제 하나님께서 영원히 거하시겠다는 약속이 주어집니다. 포로 생활의 절망 속에서도 하나님은 결코 자기 백성을 포기하지 않으셨습니다.\n\n오늘 우리의 삶에도 무너진 것들이 있을 수 있습니다. 깨어진 관계, 좌절된 꿈, 실패한 계획들... 그러나 에스겔이 본 환상은 하나님께서 폐허 위에 새로운 질서를 세우시는 분임을 보여줍니다. 중요한 것은 사독의 자손들처럼 어두운 때에도 맡은 자리를 지키는 신실함입니다. 하나님은 그런 이들과 함께 새 역사를 쓰기 원하십니다. 오늘도 ''여호와 삼마'' - 하나님이 함께하시는 그 약속을 붙들고 살아갑시다.', E'오늘의 핵심\n에스겔이 본 새 예루살렘의 환상은 하나님께서 자기 백성과 영원히 함께 거하시겠다는 언약의 완성을 보여줍니다.\n\n묵상 질문\n1. 모든 지파에게 동등하게 땅을 분배하시는 하나님의 공평하심이 내 삶에는 어떻게 나타나고 있나요?\n2. 어두운 시대에도 신실함을 지킨 사독의 자손들처럼, 나는 지금 맡은 자리를 충실히 지키고 있나요?\n3. ''여호와 삼마'' - 하나님이 함께 계신다는 약속이 오늘 내게 주는 위로와 소망은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-19', E'바벨론 제국에서의 위인 (다니엘 1장)', E'다니엘 1장', E'유다가 바벨론에 의해 멸망하고 많은 백성이 포로로 끌려가는 참담한 역사가 펼쳐집니다. 바벨론 제국은 정복한 나라의 인재들을 선발하여 바벨론식 교육을 시킨 후, 그들의 고국을 다스리는 관리로 활용하는 정책을 펼쳤습니다. 이에 따라 유다의 왕족과 귀족 중에서 용모가 수려하고 지혜로운 소년들이 선발되었고, 그중에는 다니엘과 하나냐, 미사엘, 아사랴가 있었습니다.\n\n바벨론 왕궁에서의 교육은 단순한 학문 교육이 아니었습니다. 갈대아의 학문과 언어를 배우는 것은 물론, 왕의 음식과 포도주를 먹으며 바벨론의 문화에 완전히 동화되도록 하는 과정이었습니다. 심지어 그들의 이름마저 바벨론식으로 바뀌었습니다. 다니엘은 벨드사살로, 하나냐는 사드락으로, 미사엘은 메삭으로, 아사랴는 아벳느고로 개명되었습니다. 이는 그들의 정체성을 뿌리째 바꾸려는 시도였습니다.\n\n그러나 다니엘은 이런 상황에서 놀라운 결단을 내립니다. "뜻을 정하여 왕의 음식과 그가 마시는 포도주로 자기를 더럽히지 아니하리라"(단 1:8) 결심한 것입니다. 포로의 신분으로서 왕의 명령을 거역하는 것은 생명을 걸어야 하는 일이었습니다. 그럼에도 다니엘은 하나님께 대한 신앙의 순수함을 지키기로 결단했습니다.\n\n놀랍게도 하나님께서는 다니엘이 환관장에게 은혜와 긍휼을 얻도록 역사하셨습니다. 열흘간의 시험 기간을 거쳐, 채식과 물만으로 생활한 다니엘과 세 친구들의 얼굴은 왕의 진미를 먹은 다른 소년들보다 더욱 건강하고 윤택했습니다. 이는 단순히 음식의 문제가 아니라 하나님께서 그들의 신앙적 결단을 기뻐하시고 축복하신 결과였습니다.\n\n하나님께서는 이들에게 특별한 은사를 더하셨습니다. 모든 학문과 지혜에 뛰어나게 하셨고, 특별히 다니엘에게는 환상과 꿈을 해석하는 능력까지 주셨습니다. 왕이 시험해 본 결과, 그들의 지혜와 총명은 바벨론 전국의 박수와 술객보다 열 배나 뛰어났습니다. 포로로 끌려온 소년들이 오히려 제국의 중심에서 하나님의 영광을 드러내는 도구가 된 것입니다.', E'오늘의 핵심\n포로의 절망적 상황 속에서도 신앙의 순수함을 지키겠다는 다니엘의 결단은 하나님의 특별한 은혜와 축복으로 이어졌습니다.\n\n묵상 질문\n1. 신앙의 타협을 요구받는 상황에서 다니엘처럼 ''뜻을 정하는'' 결단이 필요한 영역은 무엇인가요?\n2. 하나님께서는 신앙을 지키려는 우리의 작은 결단에 어떻게 응답하시나요?\n3. 세상의 가치관에 동화되지 않고 하나님의 자녀로서의 정체성을 지키기 위해 무엇을 실천하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-20', E'바벨론 제국에서의 위인 (다니엘 2장)', E'다니엘 2장', E'느부갓네살 왕은 불안한 꿈으로 인해 잠을 이루지 못했습니다. 왕은 바벨론의 모든 지혜자들을 불러 꿈의 내용과 해석을 함께 요구하는 무리한 명령을 내렸습니다. 이는 단순히 꿈을 해석하는 것이 아니라 꿈 자체를 알아맞히라는 불가능한 요구였습니다. 갈대아 술사들이 "육체와 함께 살지 아니하는 신들 외에는 왕 앞에 그것을 보일 자가 없나이다"(단 2:11)라고 고백한 것처럼, 인간의 지혜로는 도저히 풀 수 없는 일이었습니다.\n\n이 위기의 순간에 다니엘은 왕에게 시간을 달라고 요청한 후 친구들과 함께 하나님께 간구했습니다. 그들의 기도는 단순히 목숨을 구하는 것이 아니라, 하늘에 계신 하나님의 긍휼하심을 구하는 것이었습니다. 하나님께서는 밤 환상으로 다니엘에게 왕의 꿈과 그 해석을 보여주셨습니다. 다니엘의 찬양 기도는 하나님이 역사의 주관자이시며, 왕들을 세우시고 폐하시는 분이심을 고백합니다.\n\n왕 앞에 선 다니엘은 먼저 인간의 지혜로는 이 일을 해결할 수 없음을 분명히 했습니다. 그리고 오직 하늘에 계신 하나님만이 은밀한 것을 나타내실 수 있다고 선포했습니다. 느부갓네살이 본 거대한 신상의 꿈은 앞으로 펼쳐질 세계 역사의 흐름을 보여주는 것이었습니다. 금으로 된 머리는 바벨론 제국을, 은으로 된 가슴과 팔은 메대-페르시아를, 놋으로 된 배와 넓적다리는 헬라 제국을, 쇠로 된 다리는 로마 제국을 상징했습니다.\n\n그러나 가장 중요한 것은 손대지 않은 돌이 모든 나라를 부수고 온 세계를 가득 채우는 장면이었습니다. 이것은 하나님께서 세우실 영원한 나라를 가리킵니다. 제국의 절정에서 느부갓네살이 받은 이 계시는 인간의 나라가 아무리 강대해도 결국은 무너지며, 오직 하나님의 나라만이 영원함을 보여줍니다. 포로로 잡혀온 다니엘을 통해 이방 왕에게 전해진 이 메시지는 고난 중에 있는 이스라엘 백성에게 큰 위로와 소망이 되었습니다.', E'오늘의 핵심\n하나님께서는 다니엘을 통해 인간 제국의 한계와 하나님 나라의 영원함을 계시하시며, 역사의 진정한 주관자가 누구인지를 선포하십니다.\n\n묵상 질문\n1. 내 삶의 불가능한 상황 속에서도 하나님께 지혜를 구하고 있나요?\n2. 다니엘처럼 위기를 기도의 기회로 삼는 믿음이 있습니까?\n3. 세상 권세가 아닌 하나님의 영원한 나라를 소망하며 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-21', E'꺾이지 않는 신앙 (다니엘 3장)', E'다니엘 3장', E'바빌론 포로기는 이스라엘 백성에게 신앙의 시험대였습니다. 특히 우상숭배가 만연한 이방 땅에서 하나님을 향한 신실함을 지킨다는 것은 때로 생명을 걸어야 하는 일이었습니다. 느부갓네살 왕이 세운 거대한 금 신상은 바로 그런 시험의 현장이었습니다. 높이가 육십 규빗(약 27미터)에 달하는 이 금 신상은 왕의 권력과 바빌론의 영광을 상징하는 우상이었고, 모든 백성은 악기 소리가 들릴 때마다 이 신상 앞에 엎드려 절해야 했습니다.\n\n다니엘의 세 친구 사드락과 메삭과 아벳느고는 이 명령 앞에서 중대한 선택의 기로에 섰습니다. 그들은 이미 바빌론 사회에서 높은 지위에 올라 있었고, 왕의 신임을 받고 있었습니다. 그러나 그들에게는 타협할 수 없는 신앙의 원칙이 있었습니다. 조상들이 범했던 우상숭배의 죄를 되풀이할 수는 없었던 것입니다. \n\n왕 앞에 끌려온 세 사람의 대답은 놀라웠습니다. "왕이여 우리가 섬기는 하나님이 계시다면 우리를 맹렬히 타는 풀무불 가운데에서 능히 건져내시겠고 왕의 손에서도 건져내시리이다. 그렇게 하지 아니하실지라도 왕이여 우리가 왕의 신들을 섬기지도 아니하고 왕이 세우신 금 신상에게 절하지도 아니할 줄을 아옵소서"(단 3:17-18). 이들의 신앙고백은 하나님의 구원하심을 확신하면서도, 설령 구원받지 못한다 할지라도 우상에게 절하지 않겠다는 절대적 헌신을 보여줍니다.\n\n평소보다 일곱 배나 뜨겁게 달군 풀무불 속에서 하나님은 신실한 종들과 함께하셨습니다. 느부갓네살이 목격한 네 번째 인물은 하나님의 임재를 나타내는 것이었습니다. 불은 그들의 결박만을 태웠을 뿐, 머리털 하나 그을리지 못했습니다. 이 놀라운 구원의 역사는 교만한 왕으로 하여금 하나님을 찬송하게 만들었고, 세 사람은 더욱 높임을 받게 되었습니다. 하나님은 신앙을 지키는 자들을 결코 버리지 않으시며, 오히려 그들을 통해 당신의 영광을 드러내십니다.', E'오늘의 핵심\n사드락과 메삭과 아벳느고는 생명의 위협 앞에서도 하나님께 대한 절대적 신뢰와 헌신을 보여주었고, 하나님은 신실한 종들과 함께하시며 그들을 통해 영광을 받으셨습니다.\n\n묵상 질문\n1. 신앙을 지키기 위해 감수해야 할 대가가 클 때, 나는 어떤 선택을 하고 있나요?\n2. "그렇게 하지 아니하실지라도"라는 고백처럼, 상황과 관계없이 하나님을 신뢰할 수 있나요?\n3. 오늘 내가 직면한 신앙의 시험 앞에서 하나님의 임재를 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-22', E'꺾이지 않는 신앙 (다니엘 4장)', E'다니엘 4장', E'느부갓네살 왕이 전 세계에 보낸 조서는 참으로 놀라운 고백으로 시작됩니다. 한때 자신의 힘과 권세를 자랑하던 바빌론의 왕이 이제는 지극히 높으신 하나님의 이적과 놀라운 일을 선포하고 있습니다. 이 조서는 그가 겪은 일련의 사건들을 통해 하나님을 진정으로 알게 된 과정을 보여줍니다.\n\n왕궁에서 평안을 누리던 느부갓네살에게 하나님께서는 또 다른 꿈을 주십니다. 하늘까지 닿을 만큼 크고 견고한 나무가 베이고, 그 그루터기만 남아 일곱 때를 지내게 된다는 꿈이었습니다. 바빌론의 모든 지혜자들이 해석하지 못한 이 꿈의 의미를 다니엘은 정확하게 풀어냅니다. 그 거대한 나무는 바로 느부갓네살 자신이었고, 그가 교만으로 인해 하나님의 심판을 받게 될 것이라는 예언이었습니다.\n\n다니엘은 왕에게 공의를 행하고 가난한 자를 긍휼히 여김으로 평안을 구하라고 권면합니다. 그러나 열두 달이 지난 후, 왕궁 지붕을 거닐며 "이 큰 바벨론은 내가 능력과 권세로 건설하여 나의 도성으로 삼고 이것으로 내 위엄의 영광을 나타낸 것이 아니냐"(단 4:30)라고 자만하던 그 순간, 하나님의 심판이 즉시 임했습니다. 왕은 사람에게서 쫓겨나 일곱 때 동안 들짐승과 함께 지내며 소처럼 풀을 먹게 되었습니다.\n\n정해진 기한이 차고 느부갓네살이 하늘을 우러러보았을 때, 그의 총명이 회복되었습니다. 그는 비로소 지극히 높으신 하나님이 인간의 나라를 다스리시며, 자기 뜻대로 왕위를 주시고 빼앗으신다는 진리를 깨달았습니다. 회복된 왕은 하나님을 찬양하며 그분의 영원한 권세와 통치를 선포합니다. 하나님께서는 한 이방 왕의 교만을 꺾으시고, 그를 통해 온 세상에 자신이 진정한 주권자이심을 드러내셨습니다.', E'오늘의 핵심\n하나님께서는 교만한 느부갓네살을 낮추심으로써 모든 권세가 오직 하나님께로부터 온다는 진리를 깨닫게 하시고, 그를 통해 하나님의 주권을 만방에 선포하게 하셨습니다.\n\n묵상 질문\n1. 내가 스스로의 힘과 능력으로 이루었다고 자랑하는 것들은 무엇인가요?\n2. 하나님께서 내 교만을 꺾으시고 겸손을 가르치신 경험이 있나요?\n3. 오늘 내가 하나님의 주권을 인정하고 감사해야 할 일은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-24', E'제국 변천의 중심에 서서 (다니엘 5장)', E'다니엘 5장', E'바빌론 제국의 마지막 날이 다가오고 있었습니다. 벨사살 왕이 천 명의 귀족들을 위해 성대한 잔치를 열었을 때, 그는 아버지 느부갓네살이 예루살렘 성전에서 탈취해 온 거룩한 기명들을 가져오게 합니다. 왕과 귀족들은 하나님의 거룩한 그릇으로 술을 마시며 금, 은, 구리, 쇠, 나무, 돌로 만든 우상들을 찬양했습니다. 이는 단순한 음주 행위가 아니라 하나님의 거룩함에 대한 의도적인 모독이었습니다.\n\n바로 그 순간, 사람의 손가락이 나타나 왕궁 벽에 글자를 쓰기 시작합니다. 방금 전까지 술에 취해 있던 왕의 얼굴빛이 창백하게 변하고 무릎이 떨렸습니다. 바빌론의 모든 지혜자들이 소집되었지만 아무도 그 글을 해석하지 못합니다. 왕비의 조언으로 다니엘이 부름을 받았을 때, 그는 왕의 상급을 거절하면서도 하나님의 메시지를 분명하게 전합니다.\n\n다니엘은 먼저 느부갓네살의 교훈을 상기시킵니다. 그가 교만하여 왕위에서 쫓겨나 들짐승과 같이 되었다가 "지극히 높으신 하나님이 사람 나라를 다스리시며 자기의 뜻대로 누구든지 그 자리에 세우시는 줄"(단 5:21)을 깨달은 이야기를 들려줍니다. 그런데 벨사살은 이 모든 것을 알면서도 마음을 낮추지 않고 오히려 하늘의 주재보다 자신을 높였다는 것입니다.\n\n벽에 쓰인 ''메네 메네 데겔 우바르신''이라는 글은 하나님의 심판을 선포하는 것이었습니다. 하나님께서 왕의 나라를 끝내시고, 왕을 저울에 달아보니 부족했으며, 그 나라가 메대와 바사에게 넘어갈 것이라는 뜻이었습니다. 그날 밤 벨사살은 죽임을 당하고 메대 사람 다리오가 바빌론을 차지합니다. 역사의 주관자이신 하나님께서는 교만한 제국의 시간표를 친히 정하시고 심판하셨습니다.', E'오늘의 핵심\n하나님께서는 자신을 높이고 거룩함을 모독하는 교만한 권력자들을 심판하시며, 역사의 흥망성쇠를 주관하시는 분이심을 보여주십니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 높아진 것들은 무엇이며, 어떻게 겸손히 낮출 수 있을까요?\n2. 하나님의 거룩한 것들을 일상적으로 대하며 경외심을 잃어버린 부분은 없나요?\n3. 역사를 주관하시는 하나님을 신뢰하며 오늘 하루를 어떻게 살아갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-25', E'제국 변천의 중심에 서서 (다니엘 6장)', E'다니엘 6장', E'메대 사람 다리오가 바빌론을 정복하고 새로운 통치 체제를 구축하면서, 120명의 고관과 세 명의 총리를 임명합니다. 놀랍게도 포로로 잡혀온 유다인 다니엘이 그 총리 중 한 사람이 되었고, 그의 탁월한 행정 능력으로 인해 왕은 그를 전국을 다스리는 최고 총리로 세우려 합니다. \n\n다니엘의 승진을 시기한 관리들은 그를 제거할 구실을 찾으려 했지만, 그의 충성됨과 흠 없는 삶 앞에서 아무것도 발견할 수 없었습니다. 결국 그들은 다니엘의 신앙생활을 표적으로 삼아 교묘한 함정을 만들어냅니다. 왕 외에는 어떤 신이나 사람에게도 기도하지 못하게 하는 조서를 왕에게 제안한 것입니다.\n\n다니엘은 왕의 도장이 찍힌 조서를 알면서도 평소와 같이 하루 세 번 예루살렘을 향해 창문을 열고 무릎을 꿇어 기도합니다. 소년 시절부터 지켜온 이 신앙의 습관은 이제 그의 생명을 위협하는 올무가 되었지만, 그는 하나님께 대한 충성을 포기하지 않습니다. \n\n사자 굴에 던져진 다니엘을 위해 오히려 왕이 밤새 금식하며 잠을 이루지 못하는 모습은 참으로 역설적입니다. 이방 왕이 하나님의 종을 위해 간절히 염려하고 있는 것입니다. 새벽에 왕이 급히 달려가 부르짖을 때, 다니엘은 "나의 하나님이 이미 그의 천사를 보내어 사자들의 입을 봉하셨으므로"(단 6:22)라고 대답합니다. \n\n하나님의 기적적인 구원을 목격한 다리오 왕은 온 나라에 조서를 내려 다니엘의 하나님을 경외하도록 명령합니다. 포로로 잡혀온 한 사람의 변함없는 신앙이 이방 제국 전체에 하나님의 이름을 드높이게 한 것입니다. 다니엘의 일관된 신앙생활은 어떤 정치적 변화나 위협 속에서도 하나님의 주권을 증거하는 강력한 도구가 되었습니다.', E'오늘의 핵심\n변함없는 기도의 습관을 지킨 다니엘을 통해 하나님께서는 이방 제국에 당신의 살아계심을 증거하시고, 모든 민족이 하나님을 경외하도록 역사하십니다.\n\n묵상 질문\n1. 나의 신앙생활은 주변 상황에 관계없이 일관성을 유지하고 있나요?\n2. 신앙 때문에 손해를 감수해야 할 때, 나는 어떤 선택을 하고 있나요?\n3. 내 삶의 어떤 영역에서 다니엘처럼 꾸준한 기도의 습관을 만들어갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-26', E'다니엘의 환상과 해석 (다니엘 7장)', E'다니엘 7장', E'바벨론 왕 벨사살 원년, 다니엘은 침상에서 놀라운 환상을 보게 됩니다. 바다에서 올라온 네 짐승의 환상은 앞으로 일어날 제국들의 흥망성쇠를 보여주는 것이었습니다. 첫째 짐승은 독수리 날개를 가진 사자로, 날개가 뽑히고 사람처럼 서게 되는 모습은 교만했던 느부갓네살이 낮아진 후 회복된 바벨론을 상징합니다. 둘째 짐승인 곰은 메대와 바사를, 넷째 날개를 가진 표범은 신속하게 세계를 정복한 헬라 제국을 가리킵니다. 그리고 철 이빨을 가진 무서운 넷째 짐승은 로마 제국을 예표하는데, 특히 그 가운데서 나온 작은 뿔은 하나님을 대적하며 성도들을 핍박할 적그리스도의 모습을 보여줍니다.\n\n그러나 환상의 절정은 "옛적부터 항상 계신 이"가 보좌에 앉으시는 장면입니다. 불꽃 같은 보좌에서 심판이 시작되고, 교만한 작은 뿔은 멸망당합니다. 그리고 "인자 같은 이"가 구름을 타고 와서 영원한 나라를 받는 장면은 메시아의 궁극적 승리를 보여줍니다. 세상 제국들이 아무리 강해 보여도 결국 하나님의 주권 아래 있으며, 마침내 "지극히 높으신 이의 성도들"이 영원한 나라를 받게 될 것입니다.\n\n다니엘은 이 환상으로 인해 번민하고 얼굴빛이 변했지만, 이 일을 마음에 간직했습니다. 격동의 시대를 살아가는 하나님의 백성에게 주시는 위로와 소망의 메시지였기 때문입니다.', E'오늘의 핵심\n하나님께서는 다니엘에게 네 짐승의 환상을 통해 세상 제국들의 흥망성쇠와 함께 궁극적으로 하나님의 나라가 영원히 서게 될 것을 보여주십니다.\n\n묵상 질문\n1. 세상의 강한 권세 앞에서도 하나님의 주권을 신뢰하고 계신가요?\n2. "인자 같은 이"가 받은 영원한 나라를 바라보며 어떤 소망을 갖게 되나요?\n3. 번민스러운 현실 속에서도 하나님의 약속을 마음에 간직하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-27', E'다니엘의 환상과 해석 (다니엘 8장)', E'다니엘 8장', E'다니엘에게 첫 번째 환상이 나타난 지 2년 후, 하나님께서는 그에게 또 다른 환상을 보여주십니다. 이번에는 숫양과 숫염소의 환상이었습니다. 다니엘이 본 두 뿔 가진 숫양은 메대와 바사 제국을 상징하는 것이었고, 서쪽에서 날아온 숫염소는 헬라 제국을 가리키는 것이었습니다. 특히 숫염소의 큰 뿔은 알렉산더 대왕을, 그것이 꺾인 후 난 네 뿔은 그의 제국이 네 부분으로 나뉘어질 것을 예언하는 것이었습니다.\n\n이 환상의 핵심은 단순히 미래 역사의 전개를 보여주는 데 있지 않았습니다. 하나님께서는 제국들의 교만과 그들이 하나님의 백성을 핍박하는 모습을 보여주시면서, 결국 인간의 권력이 얼마나 허무한 것인지를 깨닫게 하십니다. 작은 뿔로 상징된 통치자는 "스스로 높아져서 군대의 주재를 대적하며"(단 8:11) 하나님을 대적하기까지 하지만, 결국 "사람의 손으로 말미암지 아니하고 깨지리라"는 말씀처럼 하나님의 심판을 피할 수 없게 됩니다.\n\n가브리엘 천사가 나타나 이 환상의 의미를 설명해 주었을 때, 다니엘은 그 무게를 감당하기 어려워 얼굴을 땅에 대고 엎드렸습니다. 환상을 통해 하나님의 뜻을 깨달은 후, 다니엘은 여러 날 동안 앓아누웠습니다. 그러나 회복된 후 그가 보여준 모습은 우리에게 깊은 교훈을 줍니다. 그는 곧바로 일어나 왕의 일을 보았던 것입니다.\n\n다니엘의 이러한 모습은 깊은 영성과 현실적 책임감이 조화를 이룬 신앙인의 삶을 보여줍니다. 하나님의 계시를 받을 만큼 깊은 영성을 지녔으면서도, 동시에 이방 왕국에서 충성스럽게 자신의 직무를 수행하는 모습은 오늘날 우리가 추구해야 할 신앙의 모델입니다. 하나님 나라의 비전을 품으면서도 현실 속에서 성실하게 살아가는 것, 이것이 다니엘이 우리에게 보여주는 균형 잡힌 신앙생활의 모습입니다.', E'오늘의 핵심\n하나님께서는 다니엘에게 제국들의 흥망성쇠를 보여주시면서 인간 권력의 한계와 하나님의 주권을 깨닫게 하십니다. 환상을 본 후에도 현실의 책임을 다하는 다니엘의 모습은 균형 잡힌 신앙생활의 모범을 보여줍니다.\n\n묵상 질문\n1. 하나님께서 다니엘에게 미래의 역사를 보여주신 이유는 무엇일까요?\n2. 깊은 영적 체험 후에도 일상의 책임을 성실히 감당하는 삶을 살고 있나요?\n3. 세상 권력의 교만함을 보면서도 하나님의 주권을 신뢰하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-28', E'미래의 일들 (다니엘 10장)', E'다니엘 10장', E'고레스 왕 제삼년, 이스라엘 백성의 귀환이 이루어진 지 삼 년이 지났습니다. 예루살렘에서는 성전 재건이 시작되었지만 주변국들의 방해로 어려움을 겪고 있던 시기였습니다. 이런 상황에서 다니엘에게 큰 전쟁에 관한 환상이 보입니다. 그는 세 이레 동안 금식하며 간절히 기도했습니다. 힛데겔 강가에서 기도하던 다니엘에게 세마포 옷을 입은 한 천사가 나타났고, 그 영광스러운 모습 앞에서 다니엘은 기력을 잃고 쓰러졌습니다.\n\n천사는 떨고 있는 다니엘을 일으켜 세우며 놀라운 말씀을 전합니다. "큰 은총을 받은 사람 다니엘아 두려워하지 말라"(단 10:11). 하나님께서는 다니엘이 기도하기 시작한 첫날부터 그의 기도를 들으셨다는 것입니다. 다만 바사 왕국의 군주가 이십일 일 동안 천사를 막았고, 천사장 미가엘이 도와주어서야 다니엘에게 올 수 있었습니다. 이는 우리가 알지 못하는 영적 전쟁이 하늘에서 일어나고 있음을 보여줍니다.\n\n천사는 다니엘에게 마지막 날에 이스라엘 백성이 당할 일을 알려주러 왔다고 말합니다. 이 환상의 무게에 짓눌려 다니엘은 다시 힘을 잃지만, 천사는 그를 만지며 "평안하라 강건하라"고 격려합니다. 하나님께서는 어려운 시기를 지나는 백성들에게 미래의 일들을 미리 보여주심으로써, 현재의 고난이 하나님의 계획 안에 있음을 알려주십니다. 비록 지금은 성전 재건이 중단되고 적대적인 상황이 계속되지만, 하나님께서는 자기 백성을 잊지 않으셨습니다. 오히려 그들을 위해 하늘에서 영적 전쟁이 벌어지고 있었던 것입니다.', E'오늘의 핵심\n하나님께서는 우리의 기도를 첫날부터 들으시며, 보이지 않는 영적 영역에서도 우리를 위해 일하고 계십니다. 어려운 상황 속에서도 "큰 은총을 받은 사람"이라 부르시며 평안과 강건함을 주십니다.\n\n묵상 질문\n1. 다니엘의 기도가 첫날부터 응답받았는데 왜 삼 주가 걸렸을까요? 내 기도의 응답이 더딜 때 어떤 마음을 가져야 할까요?\n2. 하나님이 다니엘을 "큰 은총을 받은 사람"이라고 부르셨습니다. 어려운 상황에서도 나는 하나님의 은총 받은 자녀임을 기억하고 있나요?\n3. 천사가 "평안하라 강건하라"고 반복해서 말했습니다. 오늘 내게 필요한 하나님의 위로는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-04-29', E'미래의 일들 (다니엘 11장)', E'다니엘 11장', E'다니엘이 받은 환상 중에서도 11장은 매우 구체적이고 상세한 미래의 역사를 보여주고 있습니다. 바사 제국 이후 헬라 제국의 등장과 분열, 그리고 남방 왕과 북방 왕 사이의 끊임없는 전쟁이 펼쳐집니다. 이 예언은 놀라울 정도로 정확하게 역사 속에서 성취되었는데, 알렉산더 대왕의 죽음 이후 그의 제국이 네 부분으로 나뉘고, 특히 이집트의 프톨레마이오스 왕조(남방 왕)와 시리아의 셀레우코스 왕조(북방 왕) 사이의 전쟁이 계속되었던 역사가 그대로 담겨 있습니다.\n\n본문은 단순히 정치적 격변만을 다루는 것이 아닙니다. 하나님께서는 이 모든 역사의 소용돌이 속에서도 자신의 백성을 주목하고 계십니다. 특히 주목할 부분은 32절의 말씀입니다. "오직 자기의 하나님을 아는 백성은 강하여 용맹을 떨치리라." 세상의 권력자들이 속임수와 폭력으로 자기 뜻을 관철시키려 할 때, 하나님을 아는 백성은 다른 종류의 강함을 보여줍니다. 그것은 무력이 아닌 신앙의 용기요, 권모술수가 아닌 진리를 향한 헌신입니다.\n\n본문은 또한 하나님의 백성이 겪게 될 고난도 숨기지 않습니다. 지혜로운 자들이 칼날과 불꽃과 사로잡힘을 당하며, 많은 이들이 몰락할 것이라고 예언합니다. 그러나 이 고난은 무의미한 것이 아닙니다. 35절은 이것이 "연단을 받아 정결하게 되며 희게 되어" 가는 과정임을 보여줍니다. 하나님의 섭리 안에서는 고난조차도 그의 백성을 정결케 하는 도구가 됩니다.\n\n이 복잡하고 어두운 역사의 파노라마를 보여주시는 이유는 무엇일까요? 그것은 하나님께서 역사의 주관자이심을 분명히 보여주기 위함입니다. 인간의 눈에는 혼돈과 우연의 연속처럼 보이는 역사도, 하나님의 관점에서는 정확한 계획과 목적 아래 진행되고 있습니다. "아직 정한 기한이 남았음이라"(35절)는 말씀은 모든 것이 하나님의 시간표 안에서 움직이고 있음을 확증해 줍니다.', E'오늘의 핵심\n역사의 모든 격변 속에서도 하나님은 자신의 백성을 주목하시며, 고난을 통해서라도 그들을 정결케 하시고 끝까지 보호하십니다.\n\n묵상 질문\n1. 세상의 권력이 요동칠 때에도 "자기의 하나님을 아는 백성"으로서 나는 어떤 강함을 가질 수 있을까요?\n2. 내가 겪는 시련이 하나님의 연단의 과정일 수 있다면, 지금 내 삶의 어려움을 어떻게 바라봐야 할까요?\n3. "아직 정한 기한이 남았다"는 하나님의 시간표를 신뢰하며, 오늘 내가 붙들어야 할 약속은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-01', E'미래의 일들 (다니엘 12장)', E'다니엘 12장', E'고레스 왕 제3년, 다니엘은 미래에 대한 환상을 보며 큰 근심에 빠져 금식하며 기도했습니다. 세계 열강들 사이의 전쟁과 하나님의 백성이 당할 환난을 미리 보았기 때문입니다. 이제 다니엘서의 마지막 장에서 하나님은 그 모든 환난 너머에 있을 궁극적인 구원과 소망을 보여주십니다.\n\n하나님께서는 먼저 개국 이래로 없던 환난의 때가 올 것이라고 말씀하십니다. 그러나 그 환난의 때에도 "네 백성 중 책에 기록된 모든 자가 구원을 받을 것이라"(단 12:1)는 약속을 주십니다. 이는 하나님의 백성이 어떤 환난 속에서도 버림받지 않으며, 하나님의 구원 계획 안에 있음을 확증하는 말씀입니다.\n\n특별히 다니엘서는 구약에서 부활에 대해 가장 명확하게 언급하는 본문 중 하나입니다. 땅의 티끌 가운데서 자는 자들이 깨어나 영생을 받는 자와 영원한 수치를 당할 자로 나뉘게 될 것을 보여줍니다. 또한 지혜 있는 자들과 많은 사람을 의로 인도한 자들이 별과 같이 영원토록 빛날 것이라는 약속도 주어집니다. 이는 현재의 고난이 영원한 영광과 비교할 수 없음을 일깨워줍니다.\n\n다니엘이 이 모든 환상의 의미를 다 깨닫지 못하여 "이 모든 일의 결국이 어떠하겠나이까" 묻자, 하나님은 이 말씀을 마지막 때까지 간수하고 봉함하라고 하십니다. 그리고 환난의 때에 많은 사람이 연단을 받아 정결케 될 것이며, 지혜 있는 자는 깨달을 것이라 말씀하십니다.\n\n다니엘서의 마지막 말씀은 "너는 가서 마지막을 기다리라"는 것입니다. 평안히 쉬다가 끝날에는 자기 몫을 누리게 될 것이라는 약속과 함께 주어진 이 명령은, 현재의 어려움 속에서도 인내하며 소망 중에 기다려야 함을 가르쳐줍니다. 하나님의 구원 역사는 반드시 완성될 것이며, 그의 백성은 영원한 생명과 영광에 참여하게 될 것입니다.', E'오늘의 핵심\n다니엘서는 개국 이래 없던 환난이 올 것을 예고하면서도, 하나님의 백성이 구원받을 것과 부활의 소망, 그리고 영원한 영광의 약속으로 마무리됩니다.\n\n묵상 질문\n1. 환난의 때에도 "책에 기록된 자"는 구원받는다는 약속이 오늘 나에게 어떤 위로와 확신을 주나요?\n2. "지혜 있는 자"와 "많은 사람을 의로 인도한 자"가 별과 같이 빛난다는 말씀을 묵상할 때, 내 삶의 우선순위는 어떻게 재정립되어야 할까요?\n3. "가서 마지막을 기다리라"는 말씀처럼, 현재의 어려움 속에서도 평안함을 누리며 소망 중에 기다릴 수 있는 비결은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-02', E'호세아의 결혼과 하나님의 사랑 (호세아 1장)', E'호세아 1장', E'호세아서는 하나님께서 선지자에게 매우 특별하고도 충격적인 명령을 내리시는 것으로 시작됩니다. "너는 가서 음란한 여자를 맞이하여 음란한 자식들을 낳으라"(호 1:2)는 말씀이었습니다. 이 명령은 단순히 한 개인의 결혼 이야기가 아니라, 북이스라엘을 향한 하나님의 아픈 마음을 보여주는 살아있는 비유였습니다.\n\n호세아가 맞이한 고멜은 바알 숭배와 연관된 음란한 여인이었습니다. 그녀와의 결혼은 호세아에게 평생의 고통과 수치를 안겨주었을 것입니다. 그런데 하나님께서는 바로 이 고통스러운 결혼을 통해 당신의 백성을 향한 마음을 드러내고자 하셨습니다. 이스라엘이 하나님과의 언약을 배반하고 우상을 섬기는 모습이 곧 고멜의 음란함과 같았기 때문입니다.\n\n고멜이 낳은 세 자녀의 이름은 각각 하나님의 심판을 예고합니다. 첫째 아들 ''이스르엘''은 예후가 이스르엘에서 벌인 유혈 사태를 상기시키며, 북이스라엘의 멸망을 예고합니다. 둘째 딸 ''로루하마''(긍휼히 여김을 받지 못함)와 셋째 아들 ''로암미''(내 백성이 아님)의 이름은 하나님께서 언약 백성과의 관계를 끊으시겠다는 선언이었습니다.\n\n그러나 놀랍게도 1장의 마지막은 회복의 약속으로 끝납니다. 하나님께서는 심판 선언 직후에 "이스라엘 자손의 수가 바닷가의 모래 같이 되어서 헤아릴 수도 없고 셀 수도 없을 것"이라고 말씀하십니다. ''내 백성이 아니라'' 했던 그곳에서 ''살아 계신 하나님의 아들들''이라 불릴 것이라는 약속입니다. 이것은 아브라함에게 주신 언약을 상기시키며, 심판 너머에 있는 구원의 소망을 보여줍니다.\n\n호세아의 아픈 결혼 생활은 우상 숭배로 더럽혀진 이스라엘을 여전히 사랑하시는 하나님의 마음을 보여주는 거울이었습니다. 배신당하고 상처받으면서도 끝까지 사랑하시는 하나님, 심판 중에도 회복을 약속하시는 그 신실하심이 호세아서 첫 장에 담겨 있습니다.', E'오늘의 핵심\n하나님께서는 호세아와 음란한 여인 고멜의 결혼을 통해 우상 숭배에 빠진 이스라엘을 향한 당신의 아픈 사랑과 심판, 그리고 회복의 약속을 보여주십니다.\n\n묵상 질문\n1. 호세아가 고멜과의 결혼으로 겪은 고통을 통해 하나님의 어떤 마음을 이해할 수 있을까요?\n2. 내 삶에서 하나님보다 더 의지하고 있는 ''우상''은 무엇인가요?\n3. 심판 중에도 회복을 약속하시는 하나님의 신실하심이 오늘 나에게 어떤 위로가 되나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-03', E'호세아의 결혼과 하나님의 사랑 (호세아 2장)', E'호세아 2장', E'호세아 2장은 하나님과 이스라엘의 관계를 부부관계로 표현하면서 더욱 극적인 전환을 보여줍니다. 하나님께서는 음행하는 아내 같은 이스라엘을 향해 먼저 심판을 선언하십니다. 그들이 바알에게서 받았다고 착각하는 곡식과 포도주와 기름이 사실은 하나님께서 주신 것임을 깨닫지 못하는 어리석음을 지적하십니다. 이스라엘은 하나님의 은혜를 망각하고 그 선물을 가지고 오히려 우상을 섬기는 데 사용했습니다.\n\n하나님의 심판은 단순한 징벌이 아니라 회복을 위한 과정입니다. 가시로 길을 막고 담을 쌓아 이스라엘이 우상을 따라가지 못하게 하시는 것은, 그들이 돌이켜 본래의 남편인 하나님께로 돌아오게 하려는 사랑의 표현입니다. "내가 본 남편에게로 돌아가리니 그 때의 내 형편이 지금보다 나았음이라"(2:7)라는 깨달음에 이르도록 인도하시는 것입니다.\n\n그런데 14절부터는 놀라운 반전이 일어납니다. 심판의 메시지가 갑자기 사랑의 언어로 바뀝니다. 하나님께서 이스라엘을 광야로 데리고 가서 말로 위로하시겠다고 하십니다. 광야는 이스라엘이 하나님과 처음 사랑을 나누던 장소였습니다. 출애굽 직후 아무것도 없는 광야에서 오직 하나님만 의지하며 살았던 그 시절로 돌아가 새롭게 시작하자는 것입니다. 아골 골짜기, 곧 아간의 범죄로 절망했던 그곳을 소망의 문으로 바꾸시겠다는 약속은 하나님의 은혜가 얼마나 크신지를 보여줍니다.\n\n무엇보다 감동적인 것은 19-20절의 약속입니다. 하나님께서 이스라엘에게 다시 장가들겠다고 하시면서, 그것도 "공의와 정의와 은총과 긍휼히 여김으로" 장가들겠다고 하십니다. 배신당한 남편이 돌아온 아내를 그저 받아주는 것이 아니라, 처음보다 더 깊은 사랑으로 새로운 언약을 맺으시는 것입니다. 이것이 우리를 향한 하나님의 마음입니다.', E'오늘의 핵심\n하나님께서는 우상을 섬기며 배신한 이스라엘을 심판하시지만, 그 심판마저도 회복을 위한 사랑의 과정이며, 결국 더 깊은 언약으로 그들과 다시 하나 되기를 원하십니다.\n\n묵상 질문\n1. 내가 하나님께 받은 은혜를 잊고 다른 것에 공로를 돌렸던 적은 없나요?\n2. 하나님께서 내 인생에 가시와 담을 두신 것처럼 느껴질 때, 그것이 사랑의 표현일 수 있을까요?\n3. "공의와 정의와 은총과 긍휼"로 나와 새 언약을 맺기 원하시는 하나님께 어떻게 응답하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-04', E'호세아의 결혼과 하나님의 사랑 (호세아 3장)', E'호세아 3장', E'호세아 3장은 하나님의 놀라운 사랑의 깊이를 보여주는 충격적인 장면으로 시작됩니다. 하나님께서는 호세아에게 또다시 명령하십니다. "타인의 사랑을 받아 음녀가 된 그 여자를 사랑하라"(호 3:1). 고멜은 호세아를 떠나 다른 남자와 살고 있었습니다. 아마도 노예로 팔려 있었을지도 모릅니다. 그런 아내를 다시 찾아가 사랑하라는 것입니다.\n\n호세아는 은 열다섯 개와 보리 한 호멜 반을 주고 아내를 되찾아옵니다. 이것은 당시 노예 한 명의 몸값에 해당하는 금액이었습니다. 배신한 아내를 위해 대가를 치르는 호세아의 모습은 죄인된 우리를 위해 독생자를 아끼지 않으신 하나님의 사랑을 떠올리게 합니다.\n\n호세아는 되찾은 아내에게 조건을 제시합니다. "너는 많은 날 동안 나와 함께 지내고 음행하지 말며 다른 남자를 따르지 말라." 이것은 단순한 요구가 아니라 관계 회복을 위한 정화의 시간이었습니다. 마찬가지로 이스라엘도 왕과 지도자, 제사와 우상 없이 지내는 시간을 거쳐야 했습니다. 이 고난의 시간은 심판이면서 동시에 회복을 위한 준비였습니다.\n\n호세아서는 이스라엘의 미래에 대한 소망으로 마무리됩니다. "그 후에 이스라엘 자손이 돌아와서 그들의 하나님 여호와와 그들의 왕 다윗을 찾고." 하나님께서는 배신한 백성을 끝까지 포기하지 않으십니다. 오히려 그들이 돌아올 날을 기다리며 회복의 길을 예비하고 계십니다.\n\n우리 삶에도 하나님을 떠났던 시간들이 있습니다. 세상의 가치와 욕망을 좇아 영적인 음행을 저질렀던 순간들이 있습니다. 그러나 하나님은 우리를 찾아오십니다. 값을 치르고 우리를 되찾으시며, 관계를 회복하기 원하십니다. 오늘도 그 사랑의 손길이 우리를 향해 뻗어 있습니다.', E'오늘의 핵심\n하나님께서는 배신한 백성을 포기하지 않으시고 값을 치러 되찾으시며, 정화의 시간을 통해 관계를 회복하고자 하십니다.\n\n묵상 질문\n1. 호세아가 배신한 아내를 위해 값을 치른 것처럼, 하나님이 나를 위해 치르신 대가는 무엇인가요?\n2. 내 삶에 필요한 ''정화의 시간''은 무엇이며, 하나님은 그 시간을 통해 무엇을 회복시키려 하실까요?\n3. "마지막 날에는 여호와를 경외하므로 나아가리라"는 소망이 내 삶에 어떤 위로와 힘을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-05', E'여호와께 돌아오라', E'호세아 10장', E'호세아는 북이스라엘이 벌을 받는 이유에 대해 "그들이 두 마음을 품었으니"(호 10:2)라고 말합니다. 그들은 이제 하나님을 두려워하지도 않으며, 하나님을 왕으로 인정하지도 않습니다. 이러한 북이스라엘 백성에게 하나님께서는 "사마리아 왕은 물 위에 있는 거품 같이 멸망할 것"(호 10:7)이라고 선포하십니다. 그러나 패역한 북이스라엘을 향해 그들이 꽃처럼 피게 될 것이라고 말씀하시는 하나님의 사랑의 호소는 하나님의 진심이 어디에 있는지 알게 해줍니다.\n이제 북쪽의 앗수르가 점차 그 세력을 키우고, 제국주의를 표방하여 남하정책을 펴기 시작합니다. 곧 남북 간의 세력 균형이 깨지고 이는 전쟁으로 귀결될 것이 분명했습니다. 그 틈에 끼어 있는 북이스라엘은 전쟁에 휘싸일 가능성이 농후한 지리적 조건에 놓여 있는데도, 일시적인 평안 속에서 안주하고 있었습니다. 이때 하나님의 예언자들이 세계의 큰 흐름을 보면서 이들의 어리석음과 죄악을 지적하고 하나님의 마음을 전하였으나, 북이스라엘 백성은 끝내 순종하기를 거부합니다. 결국 여로보암 2세 시대가 끝나자, 북이스라엘은 큰 혼란 속에서 멸망을 향해 급격히 추락해 갑니다.', E'오늘의 핵심\n패역한 백성 북이스라엘을 향해 하나님께서는 사랑하는 마음을 드러내십니다. 그들이 돌아오기를 다시 한 번 간절히 호소하십니다.\n\n묵상 질문\n하나님은 심판하시면서도 왜 회복을 약속하셨을까요?\n두 마음을 품은 내 신앙은 어떤 모습인가요?\n하나님의 사랑의 호소에 응답하는 결단을 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-06', E'마음을 찢는 기도: 진정한 회개의 자리', E'요엘 2장', E'욜 2장 앞부분은 메뚜기 재앙으로 상징되는 여호와의 날을 그리고 있습니다. 땅이 진동하고, 해와 달이 캄캄해지며, "당할 자가 누구이랴"(11절)라는 절망적 선언이 이어집니다. 그런데 바로 그 직후, 12절에서 하나님은 뜻밖의 말씀을 하십니다. "너희는 이제라도… 내게로 돌아오라." 심판의 한가운데서 회복의 문을 여신 것입니다. "이제라도"라는 단어에 하나님의 간절한 마음이 담겨 있습니다. 너무 늦은 것 같은 바로 그 순간에도 돌아올 수 있다는 초대입니다.\n\n13절에서 하나님은 "옷을 찢지 말고 마음을 찢으라"고 하십니다. 당시 옷을 찢는 것은 슬픔과 회개를 표현하는 관습이었지만, 자칫 형식적 행위에 머물 수 있었습니다. 하나님이 원하시는 것은 겉으로 보이는 종교적 제스처가 아니라, 마음 깊은 곳이 찢어지는 진심 어린 돌아옴입니다. 마음을 찢는다는 것은 우리 안에 단단하게 굳어 있던 자존심, 변명, 무감각함이 깨어지는 것을 의미합니다.\n\n그리고 하나님은 그렇게 돌아오는 자에게 당신이 어떤 분이신지를 직접 말씀하십니다. "은혜로우시며 자비로우시며 노하기를 더디하시며 인애가 크시사 뜻을 돌이켜 재앙을 내리지 아니하시나니." 회개를 요구하시면서 동시에 자신의 성품을 보여주시는 것입니다. 벌을 주시려고 돌아오라 하시는 것이 아니라, 품어 주시려고 부르시는 것입니다.\n\n우리도 때로 형식적인 회개에 익숙해질 수 있습니다. 예배 중에 습관처럼 드리는 기도, 입술로만 하는 고백. 직장에서, 관계에서, 하나님 앞에서 단단하게 굳어진 내 마음의 어떤 부분이 있지는 않은지 돌아보게 됩니다. 하나님은 오늘 우리에게도 같은 질문을 하고 계십니다. "네 마음은 정말 찢어졌니?" 하나님은 바로 그 자리에서 은혜와 인애로 우리를 맞아주시는 분입니다. 오늘 내가 옷만 찢고 있는 영역은 어디인지, 진심으로 마음을 열어야 할 한 가지를 하나님 앞에 내려놓아 보십시오.', E'오늘의 핵심\n하나님은 형식적인 회개가 아니라 마음이 찢어지는 진정한 돌아옴을 원하시며, 그렇게 돌아오는 자를 은혜와 자비로 품어 주시는 분입니다.\n\n묵상 질문\n1. 하나님은 겉모습이 아닌 찢어진 마음을 보시는 분이라는 사실이 나에게 어떤 의미가 있나요?\n2. 지금 내 마음에서 진정한 회개가 일어나고 있는지 어떻게 알 수 있나요?\n3. 하나님의 은혜와 자비 앞에서 오늘 무엇을 결단하고 기도하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-08', E'나라들에 대한 심판 선언 (아모스 1장)', E'아모스 1장', E'북이스라엘이 여로보암 2세 치하에서 정치적, 경제적 번영을 구가하던 BC 8세기, 하나님께서는 남유다 드고아 출신의 목자 아모스를 북이스라엘로 보내셨습니다. 화려한 번영의 이면에는 정의가 무너지고 약자들이 짓밟히는 어두운 현실이 있었기 때문입니다. 아모스서는 "여호와께서 시온에서부터 부르짖으시며 예루살렘에서부터 소리를 내시리니"(암 1:2)라는 선포로 시작됩니다. 하나님의 심판이 시온과 예루살렘에서부터 시작되어 온 세상에 울려 퍼진다는 것입니다.\n\n아모스는 이스라엘 주변 여섯 나라를 향한 하나님의 심판을 차례로 선포합니다. 다메섹(아람), 가사(블레셋), 두로, 에돔, 암몬 - 이 나라들은 모두 이스라엘과 국경을 접하거나 역사적으로 깊은 관계를 맺어온 나라들입니다. 각 나라를 향한 심판 선고는 "서너 가지 죄로 말미암아 내가 그 벌을 돌이키지 아니하리니"라는 동일한 형식으로 시작됩니다. 이는 그들의 죄가 우발적이거나 일시적인 것이 아니라 지속적이고 반복적인 것임을 보여줍니다.\n\n주목할 점은 하나님께서 이방 나라들의 죄악까지도 세심히 살피고 계신다는 것입니다. 아람은 길르앗을 잔인하게 압제했고, 블레셋은 포로들을 노예로 팔아넘겼으며, 두로는 형제의 언약을 배반했습니다. 에돔은 형제 나라인 이스라엘을 칼로 쫓았고, 암몬은 영토 확장을 위해 임신한 여인들까지 잔혹하게 죽였습니다. 이러한 죄목들은 모두 인간의 기본적인 존엄성을 짓밟고 약자를 착취하는 비인도적 행위들입니다.\n\n하나님은 단순히 이스라엘의 하나님이 아니라 온 세상의 주권자이십니다. 그분은 모든 민족의 행위를 감찰하시며, 정의와 공의의 기준으로 심판하십니다. 이방 나라들을 향한 이러한 심판 선고는 곧 이어질 이스라엘과 유다를 향한 더 엄중한 심판의 서곡이 됩니다. 하나님의 백성이라는 특권은 더 큰 책임을 수반하기 때문입니다.', E'오늘의 핵심\n하나님께서는 이스라엘뿐 아니라 모든 나라의 불의와 폭력을 감찰하시며, 인간의 존엄성을 짓밟는 죄악들을 반드시 심판하십니다.\n\n묵상 질문\n1. 하나님께서 이방 나라들의 죄악까지 세심히 살피신다는 사실이 나에게 어떤 의미로 다가오나요?\n2. 오늘날 우리 사회에서 일어나는 약자에 대한 폭력과 착취를 보며 어떤 마음이 드나요?\n3. 정의와 공의의 하나님 앞에서 나는 어떤 책임을 감당해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-09', E'나라들에 대한 심판 선언 (아모스 2장)', E'아모스 2장', E'아모스 선지자를 통한 하나님의 심판 선언이 계속됩니다. 모압과 남유다를 거쳐 마침내 북이스라엘을 향한 준엄한 심판의 메시지가 선포됩니다. 모압은 에돔 왕의 시체를 불태워 재로 만드는 잔인한 행위로, 남유다는 하나님의 율법을 멸시하고 우상을 따른 죄로 심판받을 것입니다. \n\n그러나 가장 무서운 심판은 북이스라엘을 향합니다. "은을 받고 의인을 팔며 신 한 켤레를 받고 가난한 자를 팔며"(암 2:6)라는 하나님의 탄식에서 당시 사회의 타락상이 적나라하게 드러납니다. 재판관들이 뇌물을 받고 무죄한 사람을 유죄로 만들고, 가난한 자들의 빚을 빌미로 그들을 노예로 팔아버리는 일이 만연했습니다. 신 한 켤레 값에 불과한 작은 빚조차도 인간의 존엄성을 짓밟는 도구가 되었던 것입니다.\n\n더욱 충격적인 것은 종교적 타락입니다. 제단 옆에서 전당 잡은 옷 위에 눕고, 벌금으로 얻은 포도주를 신전에서 마시는 모습은 종교가 얼마나 부패했는지를 보여줍니다. 가난한 자의 옷을 담보로 잡아 제사 때 깔고 앉으며, 불의하게 거둔 벌금으로 종교 행사를 치르는 그들의 예배는 하나님께 역겨운 것이었습니다.\n\n하나님께서는 과거 출애굽의 은혜와 가나안 정착의 역사를 상기시키십니다. 애굽에서 구원하시고 광야에서 인도하시며 아모리 족속을 몰아내고 그 땅을 주신 분이 바로 하나님이셨습니다. 선지자와 나실인을 세워 영적 지도자로 삼으신 것도 하나님의 은혜였습니다. 그런데 이스라엘은 나실인에게 포도주를 마시게 하여 서원을 깨뜨리게 하고, 선지자의 입을 막아 예언하지 못하게 했습니다.\n\n이제 심판은 피할 수 없습니다. 곡식단을 가득 실은 수레가 땅을 누르듯 하나님의 심판이 그들을 압도할 것입니다. 그날에는 빠른 자도, 강한 자도, 용사도, 활 쏘는 자도, 말 타는 자도 모두 무력하게 될 것입니다. 인간의 그 어떤 능력도 하나님의 심판 앞에서는 아무 소용이 없음을 보여주는 장면입니다.', E'오늘의 핵심\n하나님께서는 사회적 불의와 종교적 타락으로 가득한 이스라엘에 대해 피할 수 없는 심판을 선언하시며, 과거의 은혜를 잊고 하나님을 거역한 그들의 배은망덕함을 지적하십니다.\n\n묵상 질문\n1. 작은 빚조차도 사람을 짓밟는 도구로 사용하는 우리 시대의 불의는 무엇일까요?\n2. 종교 활동이 오히려 하나님께 역겨운 것이 되는 경우는 언제일까요?\n3. 하나님의 과거 은혜를 기억하며 오늘 내가 회개해야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-10', E'나라들에 대한 심판 선언 (아모스 3장)', E'아모스 3장', E'하나님께서는 애굽에서 인도해 내신 이스라엘을 향해 특별한 관계성을 선언하십니다. "내가 땅의 모든 족속 가운데 너희만을 알았나니"(암 3:2)라는 말씀은 하나님의 선택받은 백성으로서의 특권을 보여줍니다. 그러나 이 특별한 관계는 더 큰 책임을 수반합니다. 하나님은 바로 그 특권 때문에 오히려 그들의 모든 죄악을 더욱 엄중히 다루시겠다고 선언하십니다.\n\n아모스는 일상생활에서 쉽게 볼 수 있는 인과관계의 예들을 들어 하나님의 심판이 필연적임을 설명합니다. 두 사람이 약속 없이 동행할 수 없듯이, 사자가 먹이 없이 포효하지 않듯이, 하나님의 심판 역시 이유 없이 임하지 않습니다. 이러한 자연의 법칙을 통해 하나님께서는 당신의 심판이 북이스라엘의 죄악에 대한 필연적인 결과임을 보여주십니다.\n\n특히 주목할 만한 것은 하나님께서 선지자들을 통해 미리 경고하신다는 사실입니다. 하나님은 당신의 계획을 종 선지자들에게 먼저 보이시고, 그들을 통해 백성들에게 회개의 기회를 주십니다. 그러나 사마리아의 궁궐에는 포학과 겁탈이 가득하고, 지도자들은 바른 일을 행할 줄 모릅니다. 부와 권력을 가진 자들이 약자를 착취하고 정의를 외면할 때, 하나님의 심판은 피할 수 없는 현실이 됩니다.\n\n목자가 사자에게서 양의 극히 일부만을 겨우 건져내듯이, 북이스라엘도 극소수만이 겨우 남을 것이라는 예언은 충격적입니다. 침상 모서리나 걸상의 방석처럼 사치품에 의지하던 그들의 안락한 삶은 완전히 무너질 것입니다. 벧엘의 우상 제단들과 겨울궁, 여름궁, 상아궁 같은 호화로운 건축물들도 모두 파괴될 것입니다. 이는 단순한 정치적 몰락이 아니라, 하나님과의 관계를 저버리고 불의를 행한 결과로 오는 총체적인 심판입니다.', E'오늘의 핵심\n하나님은 선택받은 백성 이스라엘에게 특권에 따르는 더 큰 책임을 물으시며, 그들의 불의와 우상숭배에 대해 피할 수 없는 심판을 선포하십니다.\n\n묵상 질문\n1. 하나님과의 특별한 관계가 더 큰 책임을 의미한다면, 오늘 나는 그 책임을 어떻게 감당하고 있나요?\n2. 내 삶의 어떤 영역에서 안락함과 사치에 안주하며 정의를 외면하고 있지는 않나요?\n3. 하나님께서 선지자의 음성을 통해 내게 주시는 경고의 메시지는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-11', E'나라들에 대한 심판 선언 (아모스 4장)', E'아모스 4장', E'아모스 선지자는 북이스라엘의 지도층을 향해 매우 충격적인 비유를 사용합니다. "바산의 암소들"이라는 표현은 당시 최고급 육우로 알려진 바산 지역의 소를 가리키는데, 이것은 사치와 풍요 속에서 살면서도 약자를 착취하는 사마리아 상류층 여인들을 향한 신랄한 비판이었습니다. 이들은 남편들에게 "술을 가져다가 우리로 마시게 하라"고 요구하면서 향락에 빠져 있었고, 그 대가로 힘없는 자들이 학대받고 가난한 자들이 압제당하는 현실을 외면했습니다.\n\n하나님께서는 이런 북이스라엘에게 여러 차례 경고의 신호를 보내셨습니다. 기근과 가뭄, 곡식의 병충해, 전염병과 전쟁까지 - 이 모든 재앙들은 단순한 자연재해나 우연한 사건이 아니라 백성들을 돌이키시려는 하나님의 간절한 부르심이었습니다. 특히 "너희가 내게로 돌아오지 아니하였느니라"는 말씀이 다섯 번이나 반복되는 것은, 하나님께서 얼마나 오래 참으시며 기다리셨는지를 보여줍니다. \n\n그러나 백성들은 형식적인 종교 행위에만 열심이었습니다. 벧엘과 길갈에서 제사를 드리고 십일조를 바치며 자발적 예물을 자랑스럽게 광고했지만, 정작 하나님이 원하시는 정의와 공의는 없었습니다. 겉으로는 경건해 보였지만 속으로는 썩어가는 신앙의 모습이었습니다. 결국 하나님은 "네 하나님 만나기를 준비하라"는 엄중한 심판 선언을 하십니다. 산을 지으시고 바람을 창조하신 전능하신 하나님 앞에 설 준비가 되어 있는지 묻고 계신 것입니다.', E'오늘의 핵심\n하나님은 사치와 불의로 가득한 북이스라엘에게 여러 재앙으로 경고하셨지만, 그들이 끝내 돌아오지 않자 최후의 심판을 선포하십니다.\n\n묵상 질문\n1. 나의 풍요로운 삶이 혹시 누군가의 희생 위에 세워진 것은 아닌지 돌아볼 수 있을까요?\n2. 하나님께서 내 삶에 보내신 경고의 신호들을 무시하고 있지는 않나요?\n3. 형식적인 신앙생활에 안주하면서 정의와 긍휼을 외면하고 있지는 않은지 점검해 볼까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-12', E'나라들에 대한 심판 선언 (아모스 5장)', E'아모스 5장', E'북이스라엘의 번영이 절정에 달했던 여로보암 2세 시대, 아모스는 처녀 이스라엘의 죽음을 애도하는 애가로 5장을 시작합니다. 화려한 경제 성장의 이면에는 정의가 쓴 쑥으로 변하고 공의가 땅에 던져진 참담한 현실이 있었습니다. 천 명이 출전하던 성읍에 백 명만 남고, 백 명이 나가던 곳에 열 명만 돌아올 것이라는 선언은 임박한 파멸의 그림자를 드리웁니다.\n\n그러나 하나님은 절망 가운데서도 생명의 길을 제시하십니다. "너희는 나를 찾으라 그리하면 살리라"는 말씀은 심판 선언 속에서도 여전히 열려 있는 은혜의 문을 보여줍니다. 벧엘과 길갈, 브엘세바로 대표되는 형식적 종교 의식이 아닌, 묘성과 삼성을 만드시고 사망의 그늘을 아침으로 바꾸시는 창조주 하나님을 찾으라는 부르심입니다.\n\n아모스가 지적하는 이스라엘의 죄악은 구체적입니다. 힘없는 자를 밟고 부당한 세를 거두며, 의인을 학대하고 뇌물을 받아 성문에서 가난한 자를 억울하게 만드는 것이었습니다. 다듬은 돌로 지은 화려한 집과 아름다운 포도원은 그들이 누리지 못할 것입니다. 불의로 쌓은 부는 결코 지속될 수 없기 때문입니다.\n\n특히 충격적인 것은 하나님께서 그들의 예배를 거부하신다는 선언입니다. 절기와 성회, 번제와 소제, 화목제까지 모든 종교 의식을 하나님은 받지 않으시겠다고 말씀하십니다. 찬양의 노랫소리와 비파 소리조차 듣지 않으시겠다는 단호한 거절은 예배와 삶의 분리가 얼마나 심각한 죄인지를 보여줍니다. 대신 하나님이 원하시는 것은 "정의를 물 같이, 공의를 마르지 않는 강 같이 흐르게" 하는 것입니다.\n\n여호와의 날을 사모하는 이들에게 아모스는 경고합니다. 그날은 빛이 아니라 어둠의 날이 될 것이며, 사자를 피하다 곰을 만나는 것처럼 피할 수 없는 심판의 날이 될 것입니다. 형식적 신앙으로 하나님의 구원을 기대하는 것은 착각일 뿐입니다. 진정한 회복은 악을 미워하고 선을 사랑하며 성문에서 정의를 세우는 구체적인 삶의 변화를 통해서만 가능합니다.', E'오늘의 핵심\n하나님은 형식적인 예배가 아닌 정의와 공의가 강물처럼 흐르는 삶을 원하시며, 진정한 회개와 변화 없이는 여호와의 날이 구원이 아닌 심판의 날이 될 것임을 경고하십니다.\n\n묵상 질문\n1. 나의 예배는 삶과 일치하고 있나요, 아니면 정의를 외면한 채 드리는 형식적 종교 행위에 그치고 있나요?\n2. 하나님께서 "정의를 물 같이 흐르게 하라"고 하실 때, 내 삶의 어떤 영역에서 정의를 실천해야 할까요?\n3. 경제적 성공과 신앙적 성숙을 혼동하고 있지는 않은지, 진정으로 하나님을 찾는 삶은 무엇인지 묵상해 보았나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-13', E'정의를 강물 같이 (아모스 6장)', E'아모스 6장', E'아모스는 북이스라엘의 지도자들을 향해 날카로운 심판의 메시지를 전합니다. "화 있을진저 시온에서 교만한 자와 사마리아 산에서 마음이 든든한 자"라는 선포로 시작되는 이 예언은, 안일과 사치에 빠진 지도층의 실상을 적나라하게 드러냅니다. 그들은 상아 침대에 누워 어린 양과 송아지를 잡아먹으며, 대접으로 포도주를 마시고 귀한 기름을 몸에 바르는 호화로운 삶을 누리고 있었습니다. 다윗처럼 악기를 만들어 연주하며 향락에 빠져 있었지만, 정작 "요셉의 환난"으로 표현되는 백성들의 고통에는 전혀 관심이 없었습니다.\n\n하나님께서는 이들의 거짓된 안전감을 지적하십니다. 그들은 갈레, 하맛, 가드 같은 주변 강국들과 자신들을 비교하며 우월감에 취해 있었고, "흉한 날이 멀다"고 여기며 심판을 외면했습니다. 그러나 아모스는 이러한 교만이 오히려 "포악한 자리로 가까워지게" 만든다고 경고합니다. 정의를 쓸개로, 공의의 열매를 쓴 쑥으로 바꾸어버린 그들의 타락상은 하나님의 진노를 불러일으켰습니다.\n\n특히 12절의 수사적 질문은 깊은 울림을 줍니다. "말들이 어찌 바위 위에서 달리겠으며 소가 어찌 거기서 밭 갈겠느냐" - 이는 북이스라엘이 얼마나 상식과 질서를 거스르는 삶을 살고 있는지를 보여주는 비유입니다. 정의와 공의라는 사회의 기본 토대를 무너뜨린 그들에게 하나님은 철저한 심판을 선언하십니다. 사로잡힘이 임할 것이며, 한 집에 열 사람이 있어도 모두 죽을 것이라는 무서운 예언이 주어집니다.\n\n이 말씀은 오늘날 우리에게도 엄중한 경고가 됩니다. 물질적 풍요와 안락함 속에서 이웃의 고통을 외면하고, 정의와 공의를 저버린 채 살아가는 것은 하나님께서 가장 미워하시는 일임을 아모스는 분명히 전해주고 있습니다.', E'오늘의 핵심\n하나님께서는 사치와 향락에 빠져 백성의 고통을 외면하는 북이스라엘 지도층의 불의를 심판하시며, 정의와 공의를 상실한 사회의 필연적 멸망을 선언하십니다.\n\n묵상 질문\n1. 나는 혹시 물질적 안락함 속에서 주변의 아픔과 불의를 못 본 척하고 있지는 않나요?\n2. 하나님께서 우리 사회에 요구하시는 정의와 공의를 위해 내가 할 수 있는 일은 무엇일까요?\n3. "요셉의 환난"에 무관심한 지도자들의 모습이 오늘날 우리에게 주는 교훈은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-15', E'정의를 강물 같이 (아모스 7장)', E'아모스 7장', E'아모스 7장은 하나님께서 북이스라엘에 내리실 심판을 세 가지 환상으로 보여주시는 것으로 시작됩니다. 첫 번째 환상에서 하나님은 왕이 풀을 벤 후 새로 돋아나는 풀을 메뚜기가 먹어치우는 재앙을 준비하십니다. 이는 백성들의 마지막 희망마저 사라지게 하는 철저한 심판이었습니다. 두 번째 환상에서는 큰 바다를 삼키고 육지까지 태우려는 불의 심판이 준비됩니다. 이 두 환상에서 아모스는 "야곱이 미약하오니 어떻게 서리이까"라며 간절히 중보기도를 드렸고, 하나님께서는 그의 기도를 들으시고 뜻을 돌이키셨습니다. 여기서 우리는 심판을 선포하시는 하나님의 마음에도 여전히 긍휼이 있음을 발견하게 됩니다.\n\n그러나 세 번째 환상은 달랐습니다. 하나님께서 다림줄을 들고 서신 모습은 더 이상 용서가 없는 최종 심판을 의미했습니다. 다림줄은 건축물의 수직을 측정하는 도구로, 하나님께서 이스라엘의 영적 상태를 정확히 측량하시겠다는 선언이었습니다. "다시는 용서하지 아니하리니"라는 하나님의 선언은 북이스라엘을 향한 마지막 심판이 확정되었음을 보여줍니다.\n\n이러한 심판의 메시지는 벧엘 제사장 아마샤의 격렬한 반발을 불러일으켰습니다. 그는 아모스를 여로보암 왕에게 모반자로 고발하고, 남쪽 유다로 돌아가라고 협박했습니다. 그러나 아모스의 대답은 담대했습니다. 자신은 직업적 선지자가 아니라 목자요 뽕나무 재배자였으나, 하나님께서 양 떼를 따르던 자신을 불러 이스라엘에게 예언하라 명하셨다는 것입니다. 이는 하나님의 부르심이 인간의 신분이나 직업을 초월한다는 것을 보여줍니다. 아모스는 오히려 아마샤와 그의 가족에게 임할 비참한 운명을 선포함으로써, 하나님의 말씀을 거부하는 자들의 결말을 분명히 했습니다.', E'오늘의 핵심\n하나님께서는 끝까지 회개하지 않는 북이스라엘에 최종 심판을 선언하시며, 평범한 목자 아모스를 통해 그 누구도 하나님의 부르심과 심판을 막을 수 없음을 보여주십니다.\n\n묵상 질문\n1. 아모스의 중보기도에 응답하시는 하나님의 마음을 통해 무엇을 느끼시나요?\n2. 하나님의 다림줄 앞에 나의 삶은 얼마나 바르게 서 있습니까?\n3. 평범한 직업인이었던 아모스의 소명이 오늘 나에게 주는 도전은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-16', E'정의를 강물 같이 (아모스 8장)', E'아모스 8장', E'여름 과일 한 광주리의 환상은 북이스라엘의 운명을 극적으로 보여줍니다. 히브리어로 ''여름 과일''(카이츠)과 ''끝''(케츠)이 비슷한 발음을 가진 것을 통해, 하나님께서는 이스라엘의 완숙한 심판의 때가 이르렀음을 선언하십니다. 더 이상 용서하지 않으시겠다는 단호한 말씀은 그동안 수없이 기회를 주셨던 하나님의 인내가 끝났음을 의미합니다.\n\n아모스가 고발하는 당시 상인들의 모습은 충격적입니다. 그들은 안식일과 월삭이 빨리 끝나기만을 기다리며, 에바(곡물 단위)는 작게 하고 세겔(화폐 단위)은 크게 하여 거짓 저울로 속입니다. 심지어 가난한 자를 신 한 켤레 값으로 사고파는 인신매매까지 서슴지 않으며, 찌꺼기 밀을 섞어 팔기도 합니다. 하나님께서 주신 안식일이 그들에게는 장사를 방해하는 걸림돌일 뿐이었습니다.\n\n이러한 불의에 대한 하나님의 심판은 철저합니다. 대낮에 해가 지는 우주적 재앙, 모든 절기와 노래가 애곡으로 변하는 비극, 그리고 무엇보다 가장 무서운 심판은 "여호와의 말씀을 듣지 못한 기갈"입니다. 사람들이 이 바다에서 저 바다까지, 북쪽에서 동쪽까지 하나님의 말씀을 구하려 헤매도 찾을 수 없게 됩니다. 물질적 풍요 속에서 영적 기근을 맞는 것, 이것이 말씀을 거부한 이들에게 임할 가장 비참한 운명입니다.\n\n사마리아의 우상과 브엘세바의 신들을 의지하던 자들의 최후가 선포됩니다. 그들은 엎드러져 다시는 일어나지 못할 것입니다. 하나님의 공의는 물같이 흘러야 하는데, 그들은 그 물길을 막고 자신들의 탐욕으로 채웠습니다. 이제 그 댓가를 치러야 할 때가 왔습니다.', E'오늘의 핵심\n하나님께서는 가난한 자를 착취하고 안식일마저 장사의 걸림돌로 여기는 이스라엘에게 가장 무서운 심판인 ''말씀의 기근''을 선포하십니다.\n\n묵상 질문\n1. 내가 하나님보다 더 중요하게 여기며 기다리는 것은 무엇인가요?\n2. 주변의 약자들을 대하는 나의 태도는 하나님의 공의를 반영하고 있나요?\n3. 하나님의 말씀이 내 삶에서 진정한 양식이 되고 있는지 점검해 보셨나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-17', E'정의를 강물 같이 (아모스 9장)', E'아모스 9장', E'아모스가 본 다섯 번째 환상은 무너지는 벧엘 성전의 모습으로 시작됩니다. 하나님께서 제단 곁에 서서 기둥을 치라고 명하시는 장면은 북이스라엘의 우상숭배 중심지였던 벧엘이 완전히 파괴될 것을 보여줍니다. 이 심판은 너무나 철저하여 "한 사람도 도망하지 못하며 한 사람도 피하지 못하리라"(암 9:1)는 선언이 이어집니다. 스올이든 하늘이든, 갈멜 산 꼭대기든 바다 밑이든 어디에도 피할 곳이 없다는 표현은 하나님의 심판이 얼마나 완전할 것인지를 보여줍니다.\n\n특별히 하나님께서는 이스라엘이 다른 민족들과 다르지 않다고 선언하십니다. 구스 족속처럼 여기신다는 말씀은 선민이라는 특권에 안주하며 불의를 행해온 이스라엘에 대한 준엄한 경고입니다. 하나님께서는 블레셋과 아람도 인도하셨듯이 모든 민족의 역사를 주관하시는 분이십니다. 그러므로 이스라엘의 선택받음은 특권이 아니라 더 큰 책임을 의미하는 것이었습니다.\n\n그러나 놀랍게도 이 철저한 심판의 선언 가운데서도 하나님의 자비는 빛을 발합니다. "야곱의 집은 온전히 멸하지는 아니하리라"는 약속과 함께, 체로 체질하듯 흩어진 백성 중에서 한 알갱이도 땅에 떨어지지 않게 하시겠다는 은혜의 말씀이 이어집니다. 더 나아가 무너진 다윗의 장막을 다시 세우시고, 황폐한 땅이 회복되어 파종하는 자가 추수하는 자를 따라잡을 정도로 풍성한 축복이 임할 것을 약속하십니다. 이는 단순한 물질적 회복을 넘어 하나님과의 관계가 온전히 회복될 메시아 시대의 소망을 담고 있습니다.', E'오늘의 핵심\n하나님께서는 북이스라엘에 대한 철저한 심판을 선언하시면서도, 남은 자를 통한 회복의 약속으로 끝없는 사랑과 신실하심을 보여주십니다.\n\n묵상 질문\n1. 하나님의 심판을 피할 곳이 없다는 말씀이 주는 두려움과 동시에 위로는 무엇인가요?\n2. 선민 의식에 안주하며 책임을 망각한 이스라엘의 모습에서 오늘날 교회가 배워야 할 교훈은 무엇일까요?\n3. 체로 거르시되 한 알갱이도 떨어뜨리지 않으시는 하나님의 세심한 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-18', E'열방을 향한 사랑 (요나 1장)', E'요나 1장', E'하나님의 말씀이 요나에게 임했습니다. "너는 일어나 저 큰 성읍 니느웨로 가서 그것을 향하여 외치라"(욘 1:2). 니느웨는 당시 앗수르 제국의 수도로, 이스라엘을 위협하던 가장 잔인한 도시였습니다. 그런데 요나는 정반대 방향인 다시스로 향하는 배에 몸을 실었습니다. 단순한 두려움 때문이 아니었습니다. 그는 하나님의 성품을 너무나 잘 알고 있었기에, 혹시라도 니느웨가 회개하여 구원받는 것을 원치 않았던 것입니다.\n\n하나님께서는 큰 바람을 일으켜 요나가 탄 배를 흔드셨습니다. 이방인 선원들은 각자의 신에게 부르짖으며 짐을 바다에 던져 배를 가볍게 하려 애썼지만, 정작 이 모든 일의 원인인 요나는 배 밑층에서 깊이 잠들어 있었습니다. 제비뽑기를 통해 재앙의 원인이 밝혀지자, 요나는 자신이 "바다와 육지를 지으신 하늘의 하나님 여호와를 경외하는 자"임을 고백합니다. 그러면서도 여호와의 얼굴을 피하여 도망치는 모순된 행동을 했다고 시인합니다.\n\n흥미로운 것은 이방인 선원들의 반응입니다. 그들은 요나를 바다에 던지기를 주저하며 힘써 노를 저어 육지로 돌아가려 했습니다. 하나님을 모르던 이들이 오히려 한 생명을 아끼는 마음을 보여준 것입니다. 결국 요나를 바다에 던진 후 바다가 잔잔해지자, 그들은 여호와를 크게 두려워하며 제물을 드리고 서원을 했습니다. 도망치던 선지자가 의도치 않게 이방인들에게 하나님을 증거하는 도구가 된 것입니다.\n\n하나님께서는 큰 물고기를 예비하셔서 요나를 삼키게 하셨습니다. 이는 심판이 아닌 구원의 손길이었습니다. 우리가 아무리 하나님의 뜻을 거부하고 도망쳐도, 하나님의 주권적인 사랑은 우리를 포기하지 않으십니다. 때로는 폭풍을 통해, 때로는 물고기 뱃속 같은 절망적 상황을 통해 우리를 다시 그분의 뜻 안으로 인도하십니다.', E'오늘의 핵심\n하나님의 부르심을 거부하고 도망친 요나를 통해서도 하나님은 이방인들에게 자신을 계시하시며, 폭풍과 물고기를 통해 요나를 포기하지 않으시는 주권적 사랑을 보여주십니다.\n\n묵상 질문\n1. 내가 하나님의 뜻임을 알면서도 피하고 있는 일은 무엇인가요?\n2. 요나를 구하려 애쓴 이방 선원들의 모습에서 무엇을 배울 수 있을까요?\n3. 내 삶의 폭풍 속에서도 나를 포기하지 않으시는 하나님의 사랑을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-19', E'열방을 향한 사랑 (요나 2장)', E'요나 2장', E'물고기 뱃속은 요나에게 무덤이 아니라 기도실이 되었습니다. 하나님의 명령을 거역하고 도망치던 선지자가 이제 깊은 바다 속, 거대한 물고기의 뱃속에서 하나님께 부르짖습니다. 이 기도는 단순한 구원의 호소가 아니라, 철저한 회개와 새로운 헌신의 고백입니다.\n\n요나의 기도는 "스올의 뱃속에서"(2절) 시작됩니다. 죽음의 문턱에서 그는 비로소 하나님께서 자신의 유일한 소망임을 깨닫습니다. 깊은 바다 속, 해초에 머리가 감긴 채 산의 뿌리까지 내려간 그 절망적인 순간에도 요나는 "다시 주의 성전을 바라보겠다"(4절)고 고백합니다. 이것은 단순히 예루살렘 성전으로 돌아가겠다는 의미를 넘어, 하나님과의 관계를 회복하겠다는 간절한 소망의 표현입니다.\n\n특별히 주목할 것은 요나가 이 극한의 상황을 하나님의 징계로 받아들인다는 점입니다. "주께서 나를 깊음 속 바다 가운데에 던지셨으므로"(3절)라는 고백에서 볼 수 있듯이, 그는 자신의 고난이 우연이 아니라 하나님의 주권적인 섭리 안에 있음을 인정합니다. 이러한 깨달음은 그를 진정한 회개로 이끌었고, "거짓되고 헛된 것을 숭상하는" 삶에서 돌이켜 "감사하는 목소리로" 하나님께 나아가게 합니다.\n\n요나는 마침내 "구원은 여호와께 속하였나이다"(9절)라고 선포합니다. 이것은 단지 물고기 뱃속에서의 구출만을 의미하지 않습니다. 니느웨 사람들의 구원도, 이스라엘의 구원도, 모든 구원이 오직 하나님께 속해 있다는 깊은 깨달음입니다. 자기 민족만을 위한 좁은 신앙에서 벗어나, 모든 민족을 향한 하나님의 구원 계획을 받아들이기 시작한 것입니다.\n\n하나님께서는 요나의 기도를 들으시고 물고기에게 명하여 그를 육지에 토하게 하셨습니다. 이는 단순한 육체적 구원이 아니라, 새로운 사명을 위한 재출발의 은혜였습니다. 때로 우리도 자신이 만든 물고기 뱃속 같은 곤경에 빠질 때가 있습니다. 그러나 그곳이 오히려 하나님을 더 깊이 만나는 은혜의 자리가 될 수 있음을 요나의 기도가 보여줍니다.', E'오늘의 핵심\n물고기 뱃속이라는 절망적 상황에서 요나는 진정한 회개의 기도를 드리며, 구원이 오직 여호와께 속했음을 깨닫고 새로운 순종의 삶으로 나아갑니다.\n\n묵상 질문\n1. 내 삶의 "물고기 뱃속" 같은 순간에 하나님께 어떻게 기도했나요?\n2. 요나처럼 고난을 통해 하나님의 주권을 인정하게 된 경험이 있나요?\n3. "구원은 여호와께 속하였나이다"라는 고백이 내 삶에서 어떤 의미인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-20', E'열방을 향한 사랑 (요나 3장)', E'요나 3장', E'여호와의 말씀이 두 번째로 요나에게 임했습니다. 물고기 뱃속에서 회개한 요나에게 하나님은 처음과 동일한 사명을 다시 주십니다. 이번에는 요나가 순종하여 니느웨로 향합니다. 니느웨는 사흘 동안 걸어야 할 만큼 거대한 도시였습니다. 당시 앗수르 제국의 수도로서 그 위용과 악명이 온 근동에 자자했던 곳입니다. \n\n요나는 겨우 하루 동안만 성읍을 다니며 "사십 일이 지나면 니느웨가 무너지리라"는 짧은 메시지를 외쳤습니다. 사흘 길의 도시에서 하루만 다녔다는 것은 요나가 여전히 마지못해 사명을 수행하고 있음을 보여줍니다. 그의 선포에는 회개의 촉구도, 구원의 소망도 없었습니다. 단지 심판의 선언뿐이었습니다.\n\n그런데 놀라운 일이 벌어졌습니다. 니느웨 사람들이 하나님을 믿고 금식을 선포한 것입니다. 신분의 높고 낮음을 막론하고 모두가 굵은 베 옷을 입었습니다. 왕까지도 보좌에서 내려와 왕복을 벗고 재 위에 앉았습니다. 더욱 놀라운 것은 왕이 내린 조서의 내용입니다. 사람뿐 아니라 짐승까지도 금식하며 굵은 베 옷을 입고, 무엇보다 "각기 악한 길과 손으로 행한 강포에서 떠날 것"을 명령했습니다. 이것은 단순한 종교적 의식이 아니라 삶의 진정한 변화를 추구하는 회개였습니다.\n\n"하나님이 뜻을 돌이키시고 그 진노를 그치사 우리가 멸망하지 않게 하시리라"는 왕의 고백은 이방인이 보여준 놀라운 믿음의 표현입니다. 그들은 확신할 수 없었지만 하나님의 자비에 자신들의 운명을 맡겼습니다. 그리고 하나님은 그들의 회개를 보시고 재앙을 거두셨습니다.\n\n이 장면은 우리에게 중요한 진리를 가르쳐줍니다. 구원의 역사는 전하는 사람의 열정이나 웅변에 달린 것이 아니라, 하나님의 말씀 자체가 지닌 능력과 듣는 사람의 마음을 여시는 하나님의 은혜에 달려 있다는 것입니다. 마지못해 전한 메시지조차 하나님은 사용하실 수 있으며, 가장 악명 높은 도시도 하나님 앞에서는 회개할 수 있습니다.', E'오늘의 핵심\n마지못해 전해진 심판의 메시지조차도 하나님은 니느웨의 구원을 위해 사용하셨고, 악명 높던 이방 도시가 진정한 회개로 하나님의 긍휼을 경험하게 하셨습니다.\n\n묵상 질문\n1. 요나의 성의 없는 선포에도 니느웨가 회개한 것을 보며 무엇을 깨닫게 되시나요?\n2. 니느웨 왕이 보여준 철저한 회개의 모습에서 나는 어떤 도전을 받나요?\n3. 하나님의 말씀이 내 삶과 주변에 능력으로 나타나기를 어떻게 기도하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-22', E'열방을 향한 사랑 (요나 4장)', E'요나 4장', E'니느웨가 회개하고 하나님께서 재앙을 거두신 것을 본 요나는 오히려 크게 분노합니다. 그의 기도는 놀라운 고백을 담고 있습니다. "주께서는 은혜로우시며 자비로우시며 노하기를 더디하시며 인애가 크시사 뜻을 돌이켜 재앙을 내리지 아니하시는 하나님이신 줄을 내가 알았음이니이다"(욘 4:2). 요나는 처음부터 하나님의 성품을 정확히 알고 있었습니다. 그가 다시스로 도망친 진짜 이유는 두려움이 아니라 니느웨가 구원받는 것을 원치 않았기 때문이었습니다.\n\n하나님은 분노하는 요나에게 박넝쿨의 비유를 통해 가르치십니다. 요나가 성읍 동쪽에서 니느웨의 운명을 지켜보고 있을 때, 하나님은 박넝쿨을 자라게 하셔서 그에게 그늘을 주셨습니다. 요나는 이 작은 은혜에 크게 기뻐했지만, 다음날 벌레가 그것을 갉아먹자 다시 죽기를 원할 만큼 괴로워합니다. 하나님은 이런 요나에게 물으십니다. 네가 수고하지도 않고 하룻밤에 났다가 사라진 박넝쿨도 아까워하면서, 어찌 좌우를 분변하지 못하는 십이만여 명과 많은 가축이 있는 니느웨를 내가 아끼지 않겠느냐고 말입니다.\n\n이 대조를 통해 하나님은 요나의 편협한 민족주의와 선택적 긍휼을 드러내십니다. 요나는 자신에게 유익한 작은 식물에는 애착을 가지면서도, 하나님이 창조하시고 사랑하시는 수많은 생명에는 무관심했습니다. 하나님의 긍휼은 이스라엘만을 위한 것이 아니라 모든 민족을 향한 것입니다. 그분은 심판하시는 하나님이시면서 동시에 회개하는 자를 기다리시는 자비의 하나님이십니다.\n\n요나서는 열린 결말로 끝납니다. 하나님의 질문에 요나가 어떻게 대답했는지 기록하지 않습니다. 이것은 오늘 우리에게도 던져진 질문입니다. 우리도 종종 하나님의 은혜가 ''그들''에게까지 미치는 것을 불편해하지 않습니까? 내가 정한 경계선 밖의 사람들, 용서받을 자격이 없다고 생각하는 이들에게도 하나님의 사랑은 동일하게 부어집니다. 하나님의 마음은 모든 영혼을 향해 열려 있습니다.', E'오늘의 핵심\n하나님은 박넝쿨의 비유를 통해 요나의 편협한 시각을 드러내시고, 모든 생명을 아끼시는 창조주 하나님의 넓은 사랑을 보여주십니다.\n\n묵상 질문\n1. 내가 하나님의 은혜를 ''자격 있는 사람''에게만 제한하고 있지는 않나요?\n2. 작은 개인적 유익에는 민감하면서 타인의 구원에는 무관심한 모습이 내게도 있지 않을까요?\n3. 하나님께서 아끼시는 사람을 내가 미워하거나 외면하고 있다면 어떻게 해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-23', E'영광이 빠져버린 시온 산성 (미가 1장)', E'미가 1장', E'미가는 이사야와 거의 동시대에 활동한 선지자로, 하나님의 심판이 임박했음을 선포합니다. 그의 예언은 북이스라엘의 수도 사마리아와 남유다의 수도 예루살렘을 향한 하나님의 준엄한 경고로 시작됩니다. "여호와께서 그의 처소에서 나오시고 강림하사 땅의 높은 곳을 밟으실 것이라"(미 1:3)는 선언은 하나님께서 직접 심판자로 나서실 것을 보여줍니다.\n\n미가가 전하는 심판의 이유는 명확합니다. 하나님의 백성이 우상숭배에 빠져 있었기 때문입니다. 특별히 충격적인 것은 이러한 죄악이 변방이 아닌 수도에서 시작되었다는 사실입니다. 사마리아와 예루살렘은 각각 북이스라엘과 남유다의 정치적, 종교적 중심지였습니다. 그런데 바로 그곳이 죄악의 온상이 되어버린 것입니다. 미가는 이를 가리켜 "야곱의 허물이 무엇이냐 사마리아가 아니냐 유다의 산당이 무엇이냐 예루살렘이 아니냐"라고 탄식합니다.\n\n하나님의 심판은 철저할 것입니다. 사마리아는 완전히 파괴되어 들의 무더기처럼 되고, 그들이 섬기던 우상들은 모두 부서질 것입니다. 더욱 비극적인 것은 이 심판이 사마리아에서 그치지 않고 남유다까지 확산될 것이라는 예언입니다. 미가는 이 재앙이 "유다까지도 이르고 내 백성의 성문 곧 예루살렘에도 미쳤음"을 선포합니다.\n\n선지자는 임박한 심판을 바라보며 깊은 애통 가운데 빠집니다. 그는 벌거벗은 몸으로 행하며 들개같이 애곡하고 타조같이 애통하겠다고 말합니다. 이는 단순한 감정의 표현이 아니라 백성을 향한 하나님의 마음을 대변하는 것이었습니다. 미가는 각 성읍들의 이름을 언급하며 그들에게 닥칠 재앙을 구체적으로 묘사하는데, 이는 심판이 얼마나 광범위하고 철저할 것인지를 보여줍니다.\n\n특별히 라기스는 "딸 시온의 죄의 근본"으로 지목됩니다. 라기스는 애굽과 가까운 요새 도시로서 우상숭배가 그곳을 통해 예루살렘으로 유입되었음을 암시합니다. 결국 하나님의 백성은 그들이 기뻐하던 자녀들과 이별하고 포로로 끌려가는 비극을 맞이하게 될 것입니다. 미가의 예언은 하나님을 떠난 백성의 최후가 얼마나 비참한지를 생생하게 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 신앙의 중심지가 오히려 우상숭배의 온상이 된 것을 보시고, 사마리아와 예루살렘에 철저한 심판을 선포하십니다.\n\n묵상 질문\n1. 신앙의 중심이어야 할 곳에서 죄악이 시작되는 것을 보며 어떤 경각심을 갖게 되나요?\n2. 미가처럼 시대의 죄악을 보며 애통해 본 적이 있으신가요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 ''라기스''는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-24', E'영광이 빠져버린 시온 산성 (미가 2장)', E'미가 2장', E'미가 선지자가 활동하던 시대는 부익부 빈익빈의 골이 깊어지던 때였습니다. 남유다의 지도층은 밤낮으로 악을 도모하며 힘없는 백성들의 재산을 강탈하는 일을 서슴지 않았습니다. 미가는 이러한 사회적 불의를 향해 하나님의 심판을 선포합니다.\n\n본문은 당시 권력자들의 죄악상을 적나라하게 보여줍니다. 그들은 침상에서조차 죄를 꾀하며 악을 계획했고, 날이 밝으면 곧바로 실행에 옮겼습니다. 남의 밭과 집을 탐내어 빼앗고, 사람과 그의 산업을 강탈하는 일이 일상이 되어버렸습니다. 이는 단순한 개인의 탐욕을 넘어 사회 구조적인 악이 되어가고 있었음을 보여줍니다.\n\n하나님께서는 이러한 불의에 대해 재앙을 선포하십니다. 그들이 남의 것을 빼앗았듯이, 하나님께서도 그들의 산업을 빼앗아 패역자에게 주시겠다고 말씀하십니다. 특히 주목할 것은 백성들이 하나님의 경고를 거부하며 "예언하지 말라"고 외치는 모습입니다. 그들은 자신들에게 유리한 거짓 선지자들의 달콤한 말만을 듣기 원했습니다.\n\n그러나 하나님의 공의는 결코 막을 수 없습니다. 미가는 전쟁을 피해 평안히 지나가는 자들의 겉옷을 벗기고, 부녀자들을 집에서 쫓아내며, 어린 자녀들에게서 하나님의 영광을 빼앗는 그들의 죄악을 낱낱이 고발합니다. 이는 단지 재산의 문제가 아니라 인간의 존엄성과 하나님의 영광을 훼손하는 일이었습니다.\n\n그럼에도 불구하고 본문의 마지막은 희망으로 마무리됩니다. 하나님께서는 흩어진 이스라엘의 남은 자들을 다시 모으시고, 목자가 양떼를 인도하듯 친히 그들의 왕이 되어 앞서 가시겠다고 약속하십니다. 심판 가운데서도 회복의 소망을 잃지 않으시는 하나님의 사랑이 여기에 나타납니다.', E'오늘의 핵심\n하나님께서는 가난한 자를 억압하고 약자를 착취하는 사회적 불의를 결코 용납하지 않으시며, 공의로운 심판과 함께 회복의 소망도 약속하십니다.\n\n묵상 질문\n1. 나는 혹시 나의 이익을 위해 다른 사람에게 해를 끼치고 있지는 않나요?\n2. 하나님의 말씀이 불편할 때, 나는 어떤 태도를 취하고 있나요?\n3. 오늘날 우리 사회에서 하나님의 공의가 필요한 영역은 어디일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-25', E'영광이 빠져버린 시온 산성 (미가 3장)', E'미가 3장', E'미가 선지자는 예루살렘의 지도자들을 향해 날카로운 심판의 메시지를 전합니다. 야곱의 우두머리들과 이스라엘 족속의 통치자들이 정의를 알아야 할 본분을 저버리고, 오히려 선을 미워하고 악을 기뻐하는 모습을 하나님께서는 참혹한 비유로 묘사하십니다. 백성의 가죽을 벗기고 뼈에서 살을 뜯어 먹는다는 표현은 권력자들이 얼마나 잔인하게 백성들을 착취하고 있는지를 생생하게 보여줍니다.\n\n이러한 악행은 정치 지도자들에게만 국한되지 않았습니다. 선지자들은 뇌물을 받으면 평강을 외치고, 그렇지 않으면 전쟁을 준비한다고 선포했습니다. 제사장들은 삯을 위해 교훈했고, 예언자들은 돈을 위해 점을 쳤습니다. 종교 지도자들마저 하나님의 말씀을 상품화하고 자신들의 이익을 위해 진리를 왜곡했던 것입니다. 그러면서도 그들은 "여호와께서 우리 중에 계시지 아니하냐 재앙이 우리에게 임하지 아니하리라"(미 3:11)고 말하며 거짓된 안전감에 빠져 있었습니다.\n\n이런 상황에서 미가는 여호와의 영으로 충만하여 능력과 정의와 용기로 야곱의 허물과 이스라엘의 죄를 드러냅니다. 그는 시온이 피로, 예루살렘이 죄악으로 건축되고 있음을 선포합니다. 하나님의 도성이어야 할 예루살렘이 백성들의 고혈을 짜내어 세워진 불의의 도시가 되어버린 것입니다. 미가의 예언대로 시온은 갈아엎은 밭이 되고, 예루살렘은 무더기가 되며, 성전의 산은 수풀의 높은 곳이 될 것입니다. 이는 단순한 물리적 파괴를 넘어 하나님과의 관계가 완전히 단절됨을 의미합니다. 정의와 공의를 버린 채 종교적 형식만 남은 예배는 하나님께서 받으실 수 없는 것임을 미가서는 분명히 보여주고 있습니다.', E'오늘의 핵심\n하나님께서는 백성을 착취하는 지도자들과 돈을 위해 진리를 왜곡하는 종교 지도자들의 죄악을 드러내시며, 불의로 세워진 예루살렘에 대한 심판을 선포하십니다.\n\n묵상 질문\n1. 오늘날 우리 사회와 교회 안에서 정의를 외면하고 자기 이익만을 추구하는 모습은 없는지 돌아보셨나요?\n2. 하나님의 이름으로 안전감을 느끼면서도 실제로는 불의를 행하는 이중적인 모습이 내 안에 있지는 않나요?\n3. 미가처럼 하나님의 영으로 충만하여 불의를 지적할 용기와 정의를 실천할 힘을 구하고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-26', E'열방을 향한 공의 (나훔 1장)', E'나훔 1장', E'니느웨를 향한 하나님의 심판 선언이 나훔을 통해 전해집니다. 150여 년 전 요나의 외침을 듣고 회개했던 니느웨 사람들이 다시 교만해져 하나님을 거스르고 주변 나라들을 포학하게 다스리자, 하나님께서는 그들을 향해 최종 심판을 선포하십니다. 나훔이 전하는 메시지는 하나님의 두 가지 속성을 분명히 보여줍니다. 첫째는 악을 결코 용납하지 않으시는 공의로운 심판자이시며, 둘째는 자기 백성을 보호하시는 신실한 구원자이십니다.\n\n나훔은 하나님을 "질투하시며 보복하시는 하나님"으로 소개합니다. 이는 하나님께서 자기 백성을 향한 뜨거운 사랑으로 그들을 괴롭히는 악을 결코 그냥 두지 않으신다는 의미입니다. 동시에 "노하기를 더디하시며 권능이 크신" 분으로 묘사되는데, 이는 하나님의 심판이 감정적이거나 성급한 것이 아니라 오래 참으신 후에 내리는 정의로운 판결임을 보여줍니다. 회오리바람과 광풍, 산들의 진동과 바위의 깨어짐 같은 자연현상의 묘사는 하나님의 심판이 얼마나 철저하고 완전할 것인지를 예고합니다.\n\n그러나 이 엄중한 심판의 메시지 가운데서도 하나님의 은혜는 빛납니다. "여호와는 선하시며 환난 날에 산성이시라 그는 자기에게 피하는 자들을 아시느니라"는 선언은 심판 가운데서도 하나님께 피하는 자들을 보호하시는 하나님의 신실하심을 보여줍니다. 앗수르의 멸망은 곧 유다의 해방을 의미했습니다. "아름다운 소식을 알리고 화평을 전하는 자의 발이 산 위에 있도다"라는 선포는 압제자의 멸망이 곧 하나님 백성에게는 구원의 소식임을 전합니다. 악인의 멸망과 의인의 구원이라는 하나님의 이중적 역사가 나훔서를 통해 분명히 드러나고 있습니다.', E'오늘의 핵심\n하나님은 오래 참으시지만 끝까지 회개하지 않는 악을 반드시 심판하시며, 동시에 자기에게 피하는 백성들에게는 구원의 산성이 되십니다.\n\n묵상 질문\n1. 하나님의 공의로운 심판을 믿는 것이 내 삶에 어떤 위로와 소망이 되나요?\n2. 은혜를 받고도 다시 교만해질 수 있는 인간의 연약함을 어떻게 극복할 수 있을까요?\n3. 환난 날에 하나님께 피한다는 것은 구체적으로 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-27', E'열방을 향한 공의 (나훔 2장)', E'나훔 2장', E'니느웨를 향한 하나님의 심판이 마침내 실행되는 광경이 생생하게 펼쳐집니다. 나훔은 바벨론 군대가 앗수르의 수도를 공격하는 모습을 마치 눈앞에서 보는 것처럼 예언합니다. 붉은 방패와 붉은 군복을 입은 적군이 번쩍이는 병거를 타고 미친 듯이 거리를 달리며 다가오는 모습은 한때 세계를 호령하던 앗수르에게 공포 그 자체였을 것입니다. \n\n특히 주목할 것은 "강들의 수문이 열리고 왕궁이 소멸되며"(나 2:6)라는 예언입니다. 역사가들은 실제로 티그리스 강의 범람으로 니느웨 성벽 일부가 무너졌고, 그 틈으로 바벨론 군대가 침입했다고 기록합니다. 하나님께서는 자연까지도 심판의 도구로 사용하셨던 것입니다.\n\n나훔은 앗수르를 사자에 비유합니다. 사자가 새끼들을 위해 사냥감을 찢어 굴을 채우듯, 앗수르는 주변 나라들을 약탈하여 부를 축적했습니다. 그러나 이제 그 사자의 굴은 텅 비게 될 것입니다. "은을 노략하라 금을 노략하라"는 외침 속에서 한때 찬란했던 제국의 영광이 약탈당하는 아이러니한 광경이 그려집니다.\n\n여호와께서는 "내가 네 대적이 되어"라고 선언하십니다. 아무리 강대한 제국이라도 하나님을 대적할 때는 반드시 무너집니다. 150여 년 전 요나의 경고로 회개했던 니느웨가 다시 교만해져 하나님을 떠났을 때, 결국 완전한 멸망을 맞게 된 것입니다. 하나님의 은혜를 받고도 그것을 당연하게 여기며 죄악으로 돌아간 니느웨의 운명은 오늘 우리에게도 엄중한 경고가 됩니다.', E'오늘의 핵심\n한때 세계를 호령하던 앗수르 제국도 하나님을 대적할 때는 비참한 멸망을 피할 수 없었으며, 하나님께서는 역사의 진정한 심판자이심을 보여주십니다.\n\n묵상 질문\n1. 하나님의 은혜를 받고도 다시 교만해진 니느웨처럼, 내가 은혜를 당연하게 여기고 있는 부분은 없나요?\n2. 세상의 권력과 부가 하나님 앞에서 얼마나 무력한지 깨달을 때, 나는 무엇을 의지하며 살아가야 할까요?\n3. 하나님께서 "내가 네 대적이 되어"라고 하실 때와 "내가 너와 함께 하여"라고 하실 때의 차이는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-29', E'열방을 향한 공의 (나훔 3장)', E'나훔 3장', E'나훔 선지자는 앗수르의 수도 니느웨를 향한 하나님의 마지막 심판을 선포합니다. 한때 요나의 메시지를 듣고 회개했던 이 거대한 성읍이 다시 교만과 폭력의 도시로 변질되었습니다. 나훔은 니느웨를 "피의 성"이라 부르며, 그 안에 거짓과 포악과 탈취가 가득하다고 고발합니다.\n\n전쟁의 참혹한 광경이 생생하게 그려집니다. 채찍 소리와 병거 바퀴 소리, 번쩍이는 칼과 번개 같은 창, 그리고 무수한 시체들이 거리에 널려 있는 모습은 니느웨가 받을 심판의 처참함을 보여줍니다. 나훔은 니느웨를 "마술에 능숙한 미모의 음녀"(나 3:4)에 비유하며, 그들이 군사력과 정치적 책략으로 여러 나라를 미혹하고 지배했던 죄를 드러냅니다.\n\n특히 주목할 것은 하나님께서 당시 최강국 애굽의 도시 노아몬(테베)의 멸망을 예로 드신다는 점입니다. 나일강으로 둘러싸여 천혜의 요새였고, 구스와 애굽의 막강한 군사력을 보유했던 노아몬도 결국 함락되었습니다. 이는 아무리 강대한 제국이라도 하나님의 심판을 피할 수 없음을 보여주는 역사의 교훈입니다.\n\n니느웨의 멸망은 철저할 것입니다. 상인들이 하늘의 별보다 많고 방백들이 메뚜기 떼처럼 많아도, 그들은 모두 흩어질 것입니다. 앗수르 왕의 목자들은 잠들고, 백성들은 산으로 도망가지만 그들을 모을 사람이 없을 것입니다. 가장 충격적인 것은 니느웨의 멸망 소식을 듣는 모든 이들이 손뼉을 칠 것이라는 선언입니다. 이는 앗수르가 주변 국가들에게 얼마나 잔혹하게 행했는지를 역설적으로 보여줍니다.\n\n하나님께서는 회개의 기회를 주신 후에도 돌이키지 않고 더욱 악을 행하는 자들에게는 반드시 공의로운 심판을 행하십니다. 니느웨의 운명은 하나님의 은혜를 멸시하고 교만하게 행하는 모든 이들에게 주시는 엄중한 경고입니다.', E'오늘의 핵심\n한때 요나를 통해 회개했던 니느웨가 다시 교만과 포악으로 돌아섰을 때, 하나님께서는 더 이상 참지 않으시고 철저한 심판을 선포하십니다. 은혜를 받고도 돌이키지 않는 자에게는 더 엄중한 심판이 있음을 보여줍니다.\n\n묵상 질문\n1. 내가 받은 하나님의 은혜를 당연하게 여기며 교만해진 부분은 없나요?\n2. 세상의 힘과 권력이 영원할 것 같지만, 하나님의 주권 앞에서는 어떤가요?\n3. 하나님의 공의로운 심판을 기억하며 오늘 내가 돌이켜야 할 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-30', E'의인은 믿음으로 살리라', E'하박국 1장', E'하박국은 하나님 앞에 솔직한 사람이었습니다. 눈앞에 펼쳐진 현실은 참담했습니다. 악인이 의인을 에워싸고, 정의는 굽게 행해지며, 율법은 힘을 잃어가고 있었습니다. 그래서 하박국은 부르짖습니다. "여호와여, 어느 때까지입니까?" 이 질문에는 하나님을 향한 신뢰와 동시에 현실 앞에서 느끼는 깊은 좌절이 함께 담겨 있습니다.\n\n그런데 하나님의 응답은 하박국을 더 혼란스럽게 만듭니다. 하나님께서는 이스라엘의 죄악을 다루시기 위해 바벨론이라는 사납고 성급한 민족을 일으키셨다고 말씀하십니다. 표범보다 빠르고 이리보다 사나운 그들이 심판의 도구라니, 하박국의 눈에 바벨론은 이스라엘보다 더 악한 나라였습니다. 그래서 다시 묻습니다. "악인이 자기보다 의로운 사람을 삼키는데도 잠잠하시나이까?"\n\n하박국의 이 질문은 오늘 우리의 질문이기도 합니다. 성실하게 살아가는데 부당한 일을 겪을 때, 정직함이 오히려 손해가 되는 것 같을 때, 하나님이 이 상황을 정말 보고 계신 것인지 의문이 들 때가 있습니다. 직장에서, 학교에서, 관계 속에서 "왜 하나님은 가만히 계실까"라는 물음이 올라올 수 있습니다.\n\n그러나 하나님께서는 이 질문을 거부하지 않으십니다. 오히려 역사 속에 실현될 당신의 공의를 약속하십니다. 지금 눈앞의 현실이 하나님의 통치 영역에서 벗어난 것처럼 보일지라도, 하나님은 온 세상을 공의로 다스리고 계십니다. 하박국이 그토록 두려워한 바벨론조차 하나님의 손 안에 있었습니다. 자기 힘을 신으로 삼는 그들도 결국 "지나치게 행하여 범죄"하게 되고, 하나님의 심판 아래 서게 됩니다.\n\n믿음은 모든 것을 이해한 후에 따라가는 것이 아닙니다. 이해되지 않는 현실 한가운데서도 하나님의 공의를 신뢰하며 서 있는 것입니다. 지금 내 삶에서 하나님의 침묵처럼 느껴지는 영역이 있다면, 그 자리에서 하박국처럼 솔직하게 질문하되, 끝까지 하나님의 응답을 기다리는 자리에 머물러 보시기 바랍니다.', E'오늘의 핵심\n이해할 수 없는 현실 속에서도 하나님은 공의로 세상을 다스리고 계시며, 의인은 그 신실하심을 믿음으로 붙잡고 살아갑니다.\n\n묵상 질문\n1. 하나님은 우리가 이해하지 못하는 상황 속에서도 선하신 목적을 이루고 계신다고 믿습니까?\n2. 내가 불공평하다고 느끼는 상황에서 하나님을 어떻게 신뢰할 수 있을까요?\n3. 지금 내 삶에서 하나님의 침묵 속에서도 믿음으로 살기로 결단할 수 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-05-31', E'우선순위를 기억하라 (학개 1장)', E'학개 1장', E'포로에서 돌아온 백성들이 성전 재건을 시작한 지 2년 만에 사마리아인들의 방해로 공사가 중단되었습니다. 그로부터 16년이라는 긴 세월이 흘렀습니다. 그 사이 백성들은 각자의 삶에 안주하며 자신의 집을 짓고 꾸미는 일에 열중했습니다. 바로 이때 하나님께서는 선지자 학개를 통해 날카로운 질문을 던지십니다. "이 성전이 황폐하였거늘 너희가 이 때에 판벽한 집에 거주하는 것이 옳으냐"(학 1:4).\n\n백성들은 아직 때가 이르지 않았다고 변명했지만, 하나님께서는 그들의 일상을 돌아보게 하십니다. 많이 뿌려도 수확이 적고, 먹어도 배부르지 못하며, 일해서 번 돈도 구멍 뚫린 주머니에 넣은 것처럼 사라져 버리는 현실. 이 모든 것이 하나님의 집을 황폐한 채로 두고 자신들의 안락함만 추구한 결과였습니다. 하나님께서는 가뭄과 흉작을 통해 그들의 우선순위가 잘못되었음을 깨닫게 하신 것입니다.\n\n놀라운 것은 학개의 메시지를 들은 백성들의 반응입니다. 총독 스룹바벨과 대제사장 여호수아를 비롯한 모든 백성이 하나님의 음성을 듣고 여호와를 경외하는 마음으로 돌아섰습니다. 그들이 순종의 마음을 품자 하나님께서는 즉시 "내가 너희와 함께 하노라"는 약속의 말씀을 주셨습니다. 더 나아가 하나님께서는 친히 그들의 마음을 감동시키셔서 성전 재건의 열정을 불타오르게 하셨습니다. 학개가 예언한 지 불과 23일 만에 백성들은 다시 성전 공사를 시작했습니다. 16년간 중단되었던 하나님의 일이 백성의 회개와 순종, 그리고 하나님의 감동하심을 통해 다시 시작된 것입니다.', E'오늘의 핵심\n하나님께서는 자신의 집보다 자기 집을 우선시하는 백성들을 책망하시고, 그들이 회개하고 돌이키자 함께하심의 약속과 성령의 감동으로 성전 재건의 열정을 회복시켜 주셨습니다.\n\n묵상 질문\n1. 나는 하나님의 일보다 내 일을 우선시하며 ''아직 때가 아니다''라고 변명하고 있지는 않나요?\n2. 내 삶에서 열심히 노력해도 열매가 없는 영역이 있다면, 혹시 하나님과의 관계가 우선순위에서 밀려난 것은 아닐까요?\n3. 하나님께서 "내가 너희와 함께 하노라"고 약속하실 때, 나는 어떤 순종의 결단으로 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-01', E'우선순위를 기억하라 (학개 2장)', E'학개 2장', E'성전 재건이 재개된 지 한 달이 지난 초막절 기간, 하나님의 말씀이 다시 학개를 통해 임합니다. 이제 막 기초공사를 시작한 성전을 바라보며 많은 사람들이 실망하고 있었습니다. 특히 포로로 잡혀가기 전 솔로몬 성전의 영광을 기억하는 노인들에게 초라한 기초는 눈물을 자아낼 만큼 보잘것없어 보였습니다. 그러나 하나님께서는 "스스로 굳세게 하여 일할지어다 내가 너희와 함께 하노라"(학 2:4)는 격려의 말씀으로 백성들을 위로하십니다.\n\n하나님께서는 출애굽 때 맺으신 언약을 상기시키시며, 그분의 영이 여전히 백성들 가운데 머물러 있음을 확증하십니다. 더 나아가 놀라운 약속을 주시는데, 이 성전의 나중 영광이 이전 영광보다 더 클 것이며, 모든 나라의 보배가 이 성전으로 모여들 것이라는 비전을 보여주십니다. 은과 금의 주인이신 하나님께서 친히 이 일을 이루실 것이기에, 현재의 초라함은 문제가 되지 않습니다.\n\n학개는 제사장들과의 문답을 통해 중요한 영적 원리를 가르칩니다. 거룩한 것이 닿는다고 해서 부정한 것이 거룩해지지 않지만, 부정한 것이 닿으면 거룩한 것도 부정해집니다. 이는 성전 건축을 중단했던 백성들의 모든 일이 하나님 앞에서 부정했음을 보여줍니다. 그러나 이제 성전 재건을 시작한 이날부터 하나님께서는 복을 약속하십니다.\n\n마지막으로 하나님께서는 총독 스룹바벨에게 특별한 약속을 주십니다. 열방이 진동하고 왕국들이 무너질 때, 하나님께서는 스룹바벨을 인장반지처럼 귀하게 여기실 것입니다. 이는 다윗 왕조의 회복과 메시아 왕국에 대한 소망을 담고 있으며, 궁극적으로 그리스도를 통해 성취될 하나님 나라의 약속입니다.', E'오늘의 핵심\n초라해 보이는 성전 재건 현장에서 낙심하는 백성들에게 하나님께서는 함께하심의 약속과 미래의 더 큰 영광을 보여주시며, 순종하는 자에게 복을 약속하십니다.\n\n묵상 질문\n1. 내가 하는 일이 보잘것없어 보일 때, 하나님의 임재와 약속을 붙잡고 있나요?\n2. 나의 삶에서 거룩함을 가로막는 ''부정한 것''은 무엇일까요?\n3. 하나님께서 나를 ''인장반지''처럼 귀히 여기신다는 사실이 오늘 나에게 어떤 위로와 힘을 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-02', E'이스라엘의 구원 (스가랴 1장)', E'스가랴 1장', E'스가랴서는 포로 귀환 후 침체된 성전 재건 사업을 독려하며 시작됩니다. 학개와 함께 활동한 스가랴는 백성들에게 하나님의 마음을 전하는데, 그 첫 메시지는 "너희는 내게로 돌아오라"는 간절한 부르심이었습니다. 하나님께서는 조상들의 불순종으로 인한 70년 포로 생활의 아픔을 상기시키시며, 이제는 그 악한 길에서 돌이켜 하나님께로 돌아오기를 촉구하십니다.\n\n스가랴가 본 첫 번째 환상은 화석류나무 사이에 선 붉은 말 탄 자와 그 뒤의 말들이었습니다. 이들은 온 땅을 두루 다니며 살피는 하나님의 사자들로, 온 땅이 평안하고 조용하다고 보고합니다. 이 평안함은 역설적으로 이스라엘의 고통과 대조됩니다. 열방은 안일하게 지내는데 하나님의 백성은 여전히 고난 중에 있었던 것입니다.\n\n여호와의 천사가 "언제까지 예루살렘과 유다 성읍들을 불쌍히 여기지 아니하시려 하나이까"라고 중보할 때, 하나님께서는 선한 말씀과 위로의 말씀으로 응답하십니다. 하나님은 예루살렘을 위해 크게 질투하시며, 안일한 열방들에게는 진노하신다고 선포하십니다. 그들이 하나님의 심판 도구로 쓰임받았으나 도를 넘어 이스라엘을 괴롭혔기 때문입니다.\n\n네 뿔의 환상은 이스라엘을 흩어지게 한 열강들을 상징하며, 네 명의 대장장이는 그들을 심판할 하나님의 도구를 나타냅니다. 하나님께서는 당신의 백성을 괴롭힌 나라들을 반드시 심판하실 것입니다. 무엇보다 중요한 약속은 "내가 불쌍히 여기므로 예루살렘에 돌아왔은즉 내 집이 그 가운데에 건축되리니"라는 말씀입니다. 하나님께서 먼저 돌아오셨으니, 이제 백성들도 응답해야 할 때입니다.', E'오늘의 핵심\n하나님께서는 70년의 징계 후에도 당신의 백성을 포기하지 않으시고, 먼저 예루살렘으로 돌아오셔서 회복의 은혜를 베푸십니다.\n\n묵상 질문\n1. 하나님의 "내게로 돌아오라"는 부르심에 나는 어떻게 응답하고 있나요?\n2. 내 삶의 어려움 속에서도 나를 위해 중보하시는 주님의 음성을 듣고 있나요?\n3. 먼저 돌아오신 하나님의 사랑에 감사하며 오늘 내가 돌이켜야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-03', E'이스라엘의 구원 (스가랴 2장)', E'스가랴 2장', E'포로 생활에서 돌아온 백성들이 폐허가 된 예루살렘을 바라보며 막막해하던 때, 하나님께서는 스가랴에게 놀라운 환상을 보여주십니다. 측량줄을 든 한 사람이 예루살렘의 너비와 길이를 재려고 하자, 천사가 급히 달려가 전합니다. 예루살렘은 성곽 없는 성읍이 될 것이라는 선포였습니다. 고대 근동에서 성곽이 없다는 것은 무방비 상태를 의미했지만, 하나님께서는 친히 "불로 둘러싼 성곽"이 되시겠다고 약속하십니다.\n\n이 환상은 단순한 도시 재건 계획이 아닌, 하나님 나라의 무한한 확장을 보여주고 있습니다. 사람과 가축이 너무 많아 성곽으로 담을 수 없을 만큼 번성할 것이며, 하나님께서 친히 그들의 보호자가 되실 것입니다. 더 나아가 이방 나라들까지도 여호와께 속하여 하나님의 백성이 될 것이라는 원대한 비전이 선포됩니다.\n\n특별히 주목할 것은 "너희를 범하는 자는 그의 눈동자를 범하는 것이라"는 하나님의 선언입니다. 눈동자처럼 소중히 여기시는 백성을 향한 하나님의 극진한 사랑이 드러납니다. 비록 지금은 바벨론에 흩어져 있고 예루살렘은 폐허가 되었지만, 하나님께서는 여전히 그들을 버리지 않으셨습니다.\n\n"시온의 딸아 노래하고 기뻐하라"는 격려는 절망 가운데 있던 백성들에게 소망의 노래를 부르게 합니다. 하나님께서 친히 그들 가운데 거하시겠다는 약속은 성전 재건의 의미를 넘어서는 것이었습니다. 이는 훗날 그리스도를 통해 성취될 임마누엘의 약속을 가리키고 있습니다.', E'오늘의 핵심\n하나님께서는 폐허가 된 예루살렘에 대한 회복의 비전을 보여주시며, 친히 불 성곽이 되어 보호하시고 그 가운데 거하시겠다고 약속하십니다.\n\n묵상 질문\n1. 하나님께서 성곽 대신 친히 보호자가 되신다는 약속이 오늘 나에게 어떤 의미가 있을까요?\n2. 우리를 ''눈동자''처럼 여기시는 하나님의 사랑을 어떻게 경험하고 있나요?\n3. 절망적인 상황에서도 "노래하고 기뻐하라"고 하시는 하나님의 음성에 어떻게 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-05', E'이스라엘의 구원 (스가랴 3장)', E'스가랴 3장', E'스가랴가 본 네 번째 환상은 대제사장 여호수아의 정결케 됨에 관한 것입니다. 포로에서 돌아온 백성들을 이끌고 성전 재건에 나선 여호수아는 더러운 옷을 입은 채 여호와의 천사 앞에 서 있었고, 사탄은 그의 오른편에서 그를 고발하고 있었습니다. 그러나 하나님께서는 사탄을 책망하시며 여호수아를 "불에서 꺼낸 그슬린 나무"라고 부르십니다. 이는 바벨론 포로라는 심판의 불에서 건져낸 귀한 존재임을 보여주는 표현입니다.\n\n여호수아의 더러운 옷은 단순히 개인의 죄가 아니라 이스라엘 백성 전체의 죄악을 대표하는 것이었습니다. 대제사장은 백성을 대표하여 하나님께 나아가는 자였기에, 그의 부정함은 곧 백성 전체가 하나님 앞에 합당치 못함을 의미했습니다. 그러나 놀랍게도 하나님께서는 직접 여호수아의 더러운 옷을 벗기시고 아름다운 옷으로 갈아입히시며 정결한 관을 씌워주십니다. 이는 하나님의 일방적인 은혜로 이루어지는 죄사함과 회복을 보여줍니다.\n\n더 나아가 하나님께서는 여호수아와 그의 동료 제사장들을 "예표의 사람들"이라 부르시며, 장차 오실 "내 종 싹"에 대해 말씀하십니다. 이 싹은 메시아를 가리키는 것으로, 하루 만에 이 땅의 죄악을 제거하실 분입니다. 여호수아의 정결케 됨은 단지 당시의 회복만이 아니라, 장차 메시아를 통해 이루어질 완전한 구원을 미리 보여주는 그림자였습니다. 성전 재건의 과정에서 하나님께서는 단순히 건물의 회복이 아닌, 백성의 영적 회복과 미래의 완전한 구원을 약속하고 계셨던 것입니다.', E'오늘의 핵심\n하나님께서는 죄로 더러워진 백성을 친히 정결케 하시고, 메시아를 통한 완전한 구원을 약속하십니다.\n\n묵상 질문\n1. 사탄의 고발 앞에서도 하나님이 나를 "불에서 꺼낸 그슬린 나무"로 여기신다는 것이 어떤 위로가 되나요?\n2. 내 힘으로 벗을 수 없는 "더러운 옷"을 하나님께서 벗겨주시기를 기다리고 있나요?\n3. 여호수아처럼 정결케 된 후, 하나님께서 맡기신 사명을 신실하게 감당하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-06-06', E'이스라엘의 구원 (스가랴 4장)', E'스가랴 4장', E'포로에서 돌아온 백성들이 성전 재건을 중단한 채 16년이나 지났습니다. 주변 민족들의 방해와 경제적 어려움, 그리고 무엇보다 영적 무기력이 그들을 짓누르고 있었습니다. 이런 상황에서 하나님께서는 스가랴에게 다섯 번째 환상을 보여주십니다. 순금 등잔대와 그 양옆의 두 감람나무, 그리고 끊임없이 공급되는 기름의 환상은 좌절한 백성들에게 새로운 소망의 메시지를 전해줍니다.\n\n환상 속에서 천사는 스룹바벨에게 주시는 하나님의 말씀을 전합니다. "이는 힘으로 되지 아니하며 능력으로 되지 아니하고 오직 나의 영으로 되느니라"(슥 4:6). 성전 재건이라는 거대한 과업 앞에서 인간의 힘과 능력은 한계가 명확합니다. 페르시아 제국의 정치적 압력, 주변 민족들의 적대감, 경제적 궁핍 등 산처럼 큰 장애물들이 앞을 가로막고 있었습니다. 그러나 하나님께서는 이 모든 것이 성령의 능력으로 평지가 될 것임을 약속하십니다.\n\n특별히 주목할 것은 "작은 일의 날"에 대한 하나님의 격려입니다. 솔로몬 성전의 웅장함을 기억하는 노인들에게 스룹바벨이 재건하는 성전은 초라해 보였을 것입니다. 그러나 하나님께서는 작은 시작을 멸시하지 말라고 하십니다. 스룹바벨의 손에 든 다림줄은 비록 작은 도구이지만, 그것이 하나님의 영으로 인도받을 때 위대한 일을 이루게 됩니다.\n\n환상의 중심인 순금 등잔대는 하나님의 백성을, 두 감람나무는 기름부음 받은 지도자들을 상징합니다. 감람나무에서 끊임없이 공급되는 기름은 성령의 지속적인 임재와 능력을 보여줍니다. 이는 단순히 성전 건물의 재건만이 아니라, 하나님의 백성이 빛을 발하는 공동체로 회복되는 영적 재건을 의미합니다. 온 세상에 두루 다니시는 여호와의 눈이 지켜보시는 가운데, 시작한 자가 반드시 그 일을 완성하실 것입니다.', E'오늘의 핵심\n성전 재건의 완성은 인간의 힘이나 능력이 아닌 오직 하나님의 영으로 이루어지며, 작은 시작도 하나님의 손에서는 위대한 완성으로 이어집니다.\n\n묵상 질문\n1. 내 삶에서 인간적 힘과 능력의 한계를 느끼며 좌절하는 영역은 무엇인가요?\n2. 하나님께서 "작은 일의 날"이라고 부르시는 나의 작은 순종과 헌신은 무엇일까요?\n3. 성령의 기름 부으심이 끊이지 않도록 나는 어떻게 하나님과의 관계를 유지하고 있나요?');
